use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
use sqlrustgo::{parse, ExecutionEngine, MemoryStorage};
use std::sync::Arc;

fn setup_engine(size: usize) -> ExecutionEngine {
    let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
    engine
        .execute(parse("CREATE TABLE orders (id INTEGER, amount INTEGER)").unwrap())
        .unwrap();

    for i in 0..size {
        engine
            .execute(parse(&format!("INSERT INTO orders VALUES ({}, {})", i, i * 10)).unwrap())
            .unwrap();
    }
    engine
}

fn bench_aggregate_count(c: &mut Criterion) {
    let mut group = c.benchmark_group("aggregate_count");

    for size in [100, 1000, 10000] {
        let mut engine = setup_engine(size);

        group.bench_with_input(BenchmarkId::new("count_star", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT COUNT(*) FROM orders").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

fn bench_aggregate_sum(c: &mut Criterion) {
    let mut group = c.benchmark_group("aggregate_sum");

    for size in [100, 1000, 10000] {
        let mut engine = setup_engine(size);

        group.bench_with_input(BenchmarkId::new("sum_amount", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT SUM(amount) FROM orders").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

fn bench_aggregate_avg(c: &mut Criterion) {
    let mut group = c.benchmark_group("aggregate_avg");

    for size in [100, 1000, 10000] {
        let mut engine = setup_engine(size);

        group.bench_with_input(BenchmarkId::new("avg_amount", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT AVG(amount) FROM orders").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

fn bench_aggregate_min_max(c: &mut Criterion) {
    let mut group = c.benchmark_group("aggregate_min_max");

    for size in [100, 1000, 10000] {
        let mut engine = setup_engine(size);

        group.bench_with_input(BenchmarkId::new("min_amount", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT MIN(amount) FROM orders").unwrap())
                    .unwrap()
            });
        });

        group.bench_with_input(BenchmarkId::new("max_amount", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT MAX(amount) FROM orders").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

fn bench_aggregate_multiple(c: &mut Criterion) {
    let mut group = c.benchmark_group("aggregate_multiple");

    for size in [100, 1000] {
        let mut engine = setup_engine(size);

        group.bench_with_input(BenchmarkId::new("count_sum_avg", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(
                        parse("SELECT COUNT(*), SUM(amount), AVG(amount) FROM orders").unwrap(),
                    )
                    .unwrap()
            });
        });
    }

    group.finish();
}

criterion_group!(
    benches,
    bench_aggregate_count,
    bench_aggregate_sum,
    bench_aggregate_avg,
    bench_aggregate_min_max,
    bench_aggregate_multiple
);
criterion_main!(benches);

//! v1.4.0 CBO Performance Benchmarks
//!
//! Benchmarks for comparing CBO (Cost-Based Optimization) performance
//! Target: Verify CBO optimization effectiveness
//!
//! Run: cargo bench --bench bench_cbo

use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
use sqlrustgo::{parse, ExecutionEngine, MemoryStorage};
use std::sync::Arc;

fn setup_table(engine: &mut ExecutionEngine, table_name: &str, rows: usize) {
    engine
        .execute(
            parse(&format!(
                "CREATE TABLE {} (id INTEGER, value INTEGER, name TEXT, category TEXT)",
                table_name
            ))
            .unwrap(),
        )
        .unwrap();

    for i in 0..rows {
        engine
            .execute(
                parse(&format!(
                    "INSERT INTO {} VALUES ({}, {}, 'name_{}', 'cat_{}')",
                    table_name,
                    i,
                    i % 100,
                    i,
                    i % 10
                ))
                .unwrap(),
            )
            .unwrap();
    }
}

fn setup_join_tables(engine: &mut ExecutionEngine, t1_rows: usize, t2_rows: usize) {
    engine
        .execute(parse("CREATE TABLE t1 (id INTEGER, value INTEGER, category TEXT)").unwrap())
        .unwrap();
    engine
        .execute(parse("CREATE TABLE t2 (id INTEGER, name TEXT, category TEXT)").unwrap())
        .unwrap();

    for i in 0..t1_rows {
        engine
            .execute(
                parse(&format!(
                    "INSERT INTO t1 VALUES ({}, {}, 'cat_{}')",
                    i,
                    i % 50,
                    i % 10
                ))
                .unwrap(),
            )
            .unwrap();
    }

    for i in 0..t2_rows {
        engine
            .execute(
                parse(&format!(
                    "INSERT INTO t2 VALUES ({}, 'name_{}', 'cat_{}')",
                    i,
                    i,
                    i % 10
                ))
                .unwrap(),
            )
            .unwrap();
    }
}

// ============================================================================
// CBO: Join Method Selection
// ============================================================================

fn bench_cbo_join_method(c: &mut Criterion) {
    let mut group = c.benchmark_group("cbo_join");

    // Small inner table - hash join should be preferred
    for size in [1000, 10000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_join_tables(&mut engine, size, 100);

        group.bench_with_input(
            BenchmarkId::new("small_inner", size),
            &size,
            |b, _| {
                b.iter(|| {
                    engine
                        .execute(
                            parse("SELECT t1.id, t1.value, t2.name FROM t1 JOIN t2 ON t1.category = t2.category")
                                .unwrap(),
                        )
                        .unwrap()
                });
            },
        );
    }

    // Large inner table - nested loop might be preferred
    for size in [100, 1000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_join_tables(&mut engine, size, size * 10);

        group.bench_with_input(
            BenchmarkId::new("large_inner", size),
            &size,
            |b, _| {
                b.iter(|| {
                    engine
                        .execute(
                            parse("SELECT t1.id, t1.value, t2.name FROM t1 JOIN t2 ON t1.category = t2.category")
                                .unwrap(),
                        )
                        .unwrap()
                });
            },
        );
    }

    group.finish();
}

// ============================================================================
// CBO: Index Scan vs Full Scan
// ============================================================================

fn bench_cbo_index_vs_scan(c: &mut Criterion) {
    let mut group = c.benchmark_group("cbo_scan");

    // High selectivity (small result) - index scan preferred
    for size in [1000, 10000, 100000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_table(&mut engine, "t1", size);

        group.bench_with_input(BenchmarkId::new("high_selectivity", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT * FROM t1 WHERE id = 50").unwrap())
                    .unwrap()
            });
        });
    }

    // Low selectivity (large result) - full scan preferred
    for size in [1000, 10000, 100000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_table(&mut engine, "t1", size);

        group.bench_with_input(BenchmarkId::new("low_selectivity", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT * FROM t1 WHERE value > 10").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

// ============================================================================
// CBO: Aggregation Method
// ============================================================================

fn bench_cbo_aggregation(c: &mut Criterion) {
    let mut group = c.benchmark_group("cbo_aggregate");

    // Small group count - hash aggregate
    for size in [1000, 10000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_table(&mut engine, "t1", size);

        group.bench_with_input(BenchmarkId::new("few_groups", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT category, COUNT(*) FROM t1 GROUP BY category").unwrap())
                    .unwrap()
            });
        });
    }

    // Many groups - sort aggregate
    for size in [1000, 10000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_table(&mut engine, "t1", size);

        group.bench_with_input(BenchmarkId::new("many_groups", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT id, SUM(value) FROM t1 GROUP BY id").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

// ============================================================================
// CBO: Complex Query Planning
// ============================================================================

fn bench_cbo_complex_query(c: &mut Criterion) {
    let mut group = c.benchmark_group("cbo_complex");

    // Multi-join query
    for size in [100, 1000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_table(&mut engine, "t1", size);
        setup_table(&mut engine, "t2", size);

        group.bench_with_input(
            BenchmarkId::new("multi_join", size),
            &size,
            |b, _| {
                b.iter(|| {
                    engine
                        .execute(
                            parse("SELECT t1.id, t1.value, t2.name FROM t1 JOIN t2 ON t1.category = t2.category WHERE t1.value > 50")
                                .unwrap(),
                        )
                        .unwrap()
                });
            },
        );
    }

    // Subquery optimization
    for size in [100, 1000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_table(&mut engine, "t1", size);

        group.bench_with_input(BenchmarkId::new("subquery", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(
                        parse("SELECT * FROM t1 WHERE id IN (SELECT id FROM t1 WHERE value > 50)")
                            .unwrap(),
                    )
                    .unwrap()
            });
        });
    }

    group.finish();
}

// ============================================================================
// Vectorization Performance
// ============================================================================

fn bench_vectorization_batch(c: &mut Criterion) {
    let mut group = c.benchmark_group("vectorization");

    for size in [1000, 10000, 100000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_table(&mut engine, "t1", size);

        // Batch processing test
        group.bench_with_input(BenchmarkId::new("batch_scan", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT id, value FROM t1").unwrap())
                    .unwrap()
            });
        });

        // SIMD-like operations test
        group.bench_with_input(BenchmarkId::new("simd_filter", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT * FROM t1 WHERE value > 50").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

criterion_group!(
    benches,
    // CBO Join (4 benchmarks)
    bench_cbo_join_method,
    // CBO Scan (6 benchmarks)
    bench_cbo_index_vs_scan,
    // CBO Aggregate (4 benchmarks)
    bench_cbo_aggregation,
    // CBO Complex (4 benchmarks)
    bench_cbo_complex_query,
    // Vectorization (6 benchmarks)
    bench_vectorization_batch,
);
criterion_main!(benches);

//! Columnar Storage Benchmark
//!
//! Benchmarks for column-oriented storage operations.

use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
use sqlrustgo_storage::columnar::{
    ColumnChunk, ColumnSegment, ColumnStats, CompressionType, TableStore,
};
use sqlrustgo_storage::engine::{ColumnDefinition, TableInfo};
use sqlrustgo_types::Value;
use tempfile::TempDir;

fn create_test_table_info(columns: usize) -> TableInfo {
    let cols: Vec<ColumnDefinition> = (0..columns)
        .map(|i| ColumnDefinition {
            name: format!("col_{}", i),
            data_type: "INTEGER".to_string(),
            nullable: true,
            is_unique: false,
            is_primary_key: false,
            references: None,
            auto_increment: false,
        })
        .collect();

    TableInfo {
        name: "bench_table".to_string(),
        columns: cols,
    }
}

// ============================================================================
// ColumnChunk Benchmarks
// ============================================================================

fn bench_column_chunk_insert(c: &mut Criterion) {
    let mut group = c.benchmark_group("column_chunk_insert");

    for size in [100, 1000, 10000] {
        group.bench_with_input(BenchmarkId::from_parameter(size), &size, |b, &size| {
            b.iter(|| {
                let mut chunk = ColumnChunk::with_capacity(size);
                for i in 0..size {
                    chunk.push(Value::Integer(i as i64));
                }
            });
        });
    }

    group.finish();
}

fn bench_column_chunk_insert_with_nulls(c: &mut Criterion) {
    let mut group = c.benchmark_group("column_chunk_insert_with_nulls");

    for size in [100, 1000, 10000] {
        group.bench_with_input(BenchmarkId::from_parameter(size), &size, |b, &size| {
            b.iter(|| {
                let mut chunk = ColumnChunk::with_capacity(size);
                for i in 0..size {
                    if i % 10 == 0 {
                        chunk.push_null();
                    } else {
                        chunk.push(Value::Integer(i as i64));
                    }
                }
            });
        });
    }

    group.finish();
}

fn bench_column_chunk_get(c: &mut Criterion) {
    let mut chunk = ColumnChunk::with_capacity(10000);
    for i in 0..10000 {
        chunk.push(Value::Integer(i as i64));
    }

    let mut group = c.benchmark_group("column_chunk_get");

    for size in [100, 1000, 10000] {
        group.bench_with_input(BenchmarkId::from_parameter(size), &size, |b, &size| {
            b.iter(|| {
                for i in 0..size {
                    let _ = chunk.get(i);
                }
            });
        });
    }

    group.finish();
}

// ============================================================================
// TableStore Benchmarks
// ============================================================================

fn bench_table_store_insert_row(c: &mut Criterion) {
    let mut group = c.benchmark_group("table_store_insert_row");

    for size in [100, 1000] {
        let info = create_test_table_info(10); // 10 columns
        group.bench_with_input(BenchmarkId::from_parameter(size), &size, |b, &size| {
            b.iter(|| {
                let mut store = TableStore::new(info.clone());
                for row_idx in 0..size {
                    let record: Vec<Value> = (0..10)
                        .map(|col_idx| Value::Integer((row_idx * 10 + col_idx) as i64))
                        .collect();
                    store.insert_row(&record).unwrap();
                }
            });
        });
    }

    group.finish();
}

fn bench_table_store_scan(c: &mut Criterion) {
    let info = create_test_table_info(10);
    let mut store = TableStore::new(info);

    // Insert 1000 rows
    for row_idx in 0..1000 {
        let record: Vec<Value> = (0..10)
            .map(|col_idx| Value::Integer((row_idx * 10 + col_idx) as i64))
            .collect();
        store.insert_row(&record).unwrap();
    }

    let mut group = c.benchmark_group("table_store_scan");

    group.bench_function("scan_all_columns", |b| {
        b.iter(|| {
            let mut count = 0;
            for i in 0..store.row_count() {
                if let Some(row) = store.get_row(i) {
                    count += row.len();
                }
            }
        });
    });

    group.finish();
}

fn bench_table_store_scan_columns(c: &mut Criterion) {
    let info = create_test_table_info(10);
    let mut store = TableStore::new(info);

    // Insert 1000 rows
    for row_idx in 0..1000 {
        let record: Vec<Value> = (0..10)
            .map(|col_idx| Value::Integer((row_idx * 10 + col_idx) as i64))
            .collect();
        store.insert_row(&record).unwrap();
    }

    let mut group = c.benchmark_group("table_store_scan_columns");

    // Scan single column
    group.bench_function("scan_single_column", |b| {
        b.iter(|| {
            let result = store.scan_columns(&[5]); // Only column 5
            assert_eq!(result.len(), 1000);
        });
    });

    // Scan 3 columns (projection pushdown)
    group.bench_function("scan_three_columns", |b| {
        b.iter(|| {
            let result = store.scan_columns(&[0, 5, 9]);
            assert_eq!(result.len(), 1000);
            assert_eq!(result[0].len(), 3);
        });
    });

    group.finish();
}

// ============================================================================
// Serialization Benchmarks
// ============================================================================

fn bench_segment_serialize(c: &mut Criterion) {
    let temp_dir = TempDir::new().unwrap();
    let segment_path = temp_dir.path().join("segment.bin");

    // Create segment with 10000 values
    let mut chunk = ColumnChunk::with_capacity(10000);
    for i in 0..10000 {
        if i % 100 == 0 {
            chunk.push_null();
        } else {
            chunk.push(Value::Integer(i as i64));
        }
    }

    let mut group = c.benchmark_group("segment_serialize");

    for compression in [CompressionType::None, CompressionType::Zstd] {
        group.bench_function(format!("{:?}", compression), |b| {
            b.iter(|| {
                let mut segment = ColumnSegment::with_compression(0, compression);
                let stats = ColumnStatsDisk::from(chunk.stats());
                segment.set_stats(stats);
                segment.set_num_values(chunk.len() as u64);
                segment
                    .write_to_file(&segment_path, chunk.values(), chunk.null_bitmap())
                    .unwrap();
            });
        });
    }

    group.finish();
}

fn bench_segment_deserialize(c: &mut Criterion) {
    let temp_dir = TempDir::new().unwrap();
    let segment_path = temp_dir.path().join("segment.bin");

    // Create and serialize segment once
    let mut chunk = ColumnChunk::with_capacity(10000);
    for i in 0..10000 {
        if i % 100 == 0 {
            chunk.push_null();
        } else {
            chunk.push(Value::Integer(i as i64));
        }
    }

    let mut segment = ColumnSegment::with_compression(0, CompressionType::Zstd);
    let stats = ColumnStatsDisk::from(chunk.stats());
    segment.set_stats(stats);
    segment.set_num_values(chunk.len() as u64);
    segment
        .write_to_file(&segment_path, chunk.values(), chunk.null_bitmap())
        .unwrap();

    let mut group = c.benchmark_group("segment_deserialize");

    group.bench_function("zstd", |b| {
        b.iter(|| {
            let mut read_segment = ColumnSegment::new(0);
            let (values, bitmap) = read_segment.read_from_file(&segment_path).unwrap();
            assert_eq!(values.len(), 10000);
            assert!(bitmap.is_some());
        });
    });

    group.finish();
}

// ============================================================================
// Statistics Benchmarks
// ============================================================================

fn bench_column_stats_update(c: &mut Criterion) {
    let mut group = c.benchmark_group("column_stats_update");

    for size in [100, 1000, 10000] {
        group.bench_with_input(BenchmarkId::from_parameter(size), &size, |b, &size| {
            b.iter(|| {
                let mut stats = ColumnStats::new();
                for i in 0..size {
                    stats.update(&Value::Integer(i as i64), false);
                }
            });
        });
    }

    group.finish();
}

criterion_group!(
    benches,
    bench_column_chunk_insert,
    bench_column_chunk_insert_with_nulls,
    bench_column_chunk_get,
    bench_table_store_insert_row,
    bench_table_store_scan,
    bench_table_store_scan_columns,
    bench_segment_serialize,
    bench_segment_deserialize,
    bench_column_stats_update
);
criterion_main!(benches);

//! IndexScan vs SeqScan Benchmark for SQLRustGo v1.5.0
//!
//! PB-02: 索引性能对比测试
//! 验证 IndexScan 性能显著优于 SeqScan

use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
use sqlrustgo::{parse, ExecutionEngine, MemoryStorage};
use std::sync::Arc;

fn setup_engine_with_data(rows: usize) -> ExecutionEngine {
    let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
    engine
        .execute(parse("CREATE TABLE idx_bench (id INTEGER, value INTEGER)").unwrap())
        .unwrap();

    for i in 0..rows {
        engine
            .execute(parse(&format!("INSERT INTO idx_bench VALUES ({}, {})", i, i * 10)).unwrap())
            .unwrap();
    }

    engine
}

fn bench_seq_scan_point_query(c: &mut Criterion) {
    let row_counts = [1000, 10000, 100000];
    let mut group = c.benchmark_group("seq_scan_point_query");

    for rows in row_counts {
        let mut engine = setup_engine_with_data(rows);

        group.bench_with_input(BenchmarkId::new("scan", rows), &rows, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT * FROM idx_bench WHERE id = 500").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

fn bench_seq_scan_range_query(c: &mut Criterion) {
    let row_counts = [1000, 10000, 100000];
    let mut group = c.benchmark_group("seq_scan_range_query");

    for rows in row_counts {
        let mut engine = setup_engine_with_data(rows);

        group.bench_with_input(BenchmarkId::new("scan", rows), &rows, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT * FROM idx_bench WHERE id > 100 AND id < 500").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

fn bench_seq_scan_high_selectivity(c: &mut Criterion) {
    let mut group = c.benchmark_group("seq_scan_high_selectivity");

    let mut engine = setup_engine_with_data(100000);

    group.bench_function("scan_1_percent", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT * FROM idx_bench WHERE id < 1000").unwrap())
                .unwrap()
        });
    });

    group.finish();
}

fn bench_seq_scan_low_selectivity(c: &mut Criterion) {
    let mut group = c.benchmark_group("seq_scan_low_selectivity");

    let mut engine = setup_engine_with_data(10000);

    group.bench_function("scan_80_percent", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT * FROM idx_bench WHERE id < 8000").unwrap())
                .unwrap()
        });
    });

    group.finish();
}

criterion_group!(
    benches,
    bench_seq_scan_point_query,
    bench_seq_scan_range_query,
    bench_seq_scan_high_selectivity,
    bench_seq_scan_low_selectivity
);
criterion_main!(benches);

//! Insert Benchmark - benches/bench_insert.rs
//!
//! INSERT performance benchmark for SQLRustGo using StorageEngine

use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
use sqlrustgo_storage::{ColumnDefinition, MemoryStorage, StorageEngine, TableInfo};
use sqlrustgo_types::Value;

/// Generate test data rows
fn generate_rows(count: usize) -> Vec<Vec<Value>> {
    (0..count).map(|i| vec![Value::Integer(i as i64)]).collect()
}

/// Create test table info
fn create_table_info() -> TableInfo {
    TableInfo {
        name: "bench".to_string(),
        columns: vec![ColumnDefinition {
            name: "id".to_string(),
            data_type: "INTEGER".to_string(),
            nullable: false,
        }],
    }
}

/// Benchmark INSERT with different data sizes using MemoryStorage
fn bench_insert_sizes(c: &mut Criterion) {
    let mut group = c.benchmark_group("insert");

    for size in [1_000, 10_000, 100_000] {
        group.bench_with_input(BenchmarkId::from_parameter(size), &size, |b, &size| {
            b.iter(|| {
                let mut storage = MemoryStorage::new();
                storage.create_table(&create_table_info()).unwrap();
                let rows = generate_rows(size);
                storage.insert("bench", rows).unwrap();
            });
        });
    }

    group.finish();
}

/// Benchmark batch INSERT performance
fn bench_insert_batch(c: &mut Criterion) {
    let mut group = c.benchmark_group("insert_batch");

    for batch_size in [10, 100, 1000] {
        let total_rows = 10_000;
        group.bench_with_input(
            BenchmarkId::from_parameter(batch_size),
            &batch_size,
            |b, &batch_size| {
                b.iter(|| {
                    let mut storage = MemoryStorage::new();
                    storage.create_table(&create_table_info()).unwrap();

                    let mut batch = Vec::with_capacity(batch_size);
                    for i in 0..total_rows {
                        batch.push(vec![Value::Integer(i as i64)]);
                        if batch.len() >= batch_size {
                            storage.insert("bench", std::mem::take(&mut batch)).unwrap();
                            batch = Vec::with_capacity(batch_size);
                        }
                    }
                    if !batch.is_empty() {
                        storage.insert("bench", batch).unwrap();
                    }
                });
            },
        );
    }

    group.finish();
}

