    pub fn get_schema(&self) -> Value {
        let tables: Vec<Value> = self
            .tables
            .values()
            .map(|t| {
                let columns: Vec<Value> = t
                    .columns
                    .iter()
                    .map(|c| {
                        let mut obj = json!({
                            "name": c.name,
                            "type": c.data_type,
                            "nullable": c.nullable,
                            "primary_key": c.primary_key,
                            "unique": c.unique,
                        });
                        if let Some(ref default) = c.default_value {
                            obj["default"] = json!(default);
                        }
                        if let Some(len) = c.max_length {
                            obj["max_length"] = json!(len);
                        }
                        if let Some(prec) = c.precision {
                            obj["precision"] = json!(prec);
                        }
                        if let Some(scale) = c.scale {
                            obj["scale"] = json!(scale);
                        }
                        if let Some(ref fk) = c.foreign_key {
                            obj["foreign_key"] = json!({
                                "table": fk.table,
                                "column": fk.column,
                            });
                        }
                        obj
                    })
                    .collect();

                let indexes: Vec<Value> = t
                    .indexes
                    .iter()
                    .map(|i| {
                        json!({
                            "name": i.name,
                            "columns": i.columns,
                            "unique": i.unique,
                            "type": i.index_type,
                        })
                    })
                    .collect();

                let mut table_obj = json!({
                    "name": t.name,
                    "columns": columns,
                    "indexes": indexes,
                });
                if let Some(ref comment) = t.comment {
                    table_obj["comment"] = json!(comment);
                }
                table_obj
            })
            .collect();

        let views: Vec<Value> = self
            .views
            .iter()
            .map(|(name, def)| {
                json!({
                    "name": name,
                    "definition": def,
                })
            })
            .collect();

        json!({
            "database": "sqlrustgo",
            "version": "1.6.1",
            "tables": tables,
            "views": views,
        })
    }

    pub fn get_table_schema(&self, table_name: &str) -> Option<Value> {
        self.tables.get(table_name).map(|t| {
            let columns: Vec<Value> = t
                .columns
                .iter()
                .map(|c| {
                    json!({
                        "name": c.name,
                        "type": c.data_type,
                        "nullable": c.nullable,
                        "primary_key": c.primary_key,
                        "unique": c.unique,
                    })
                })
                .collect();

            let indexes: Vec<Value> = t
                .indexes
                .iter()
                .map(|i| {
                    json!({
                        "name": i.name,
                        "columns": i.columns,
                        "unique": i.unique,
                        "type": i.index_type,
                    })
                })
                .collect();

            json!({
                "name": t.name,
                "columns": columns,
                "indexes": indexes,
            })
        })
    }

    pub fn list_tables(&self) -> Vec<String> {
        self.tables.keys().cloned().collect()
    }

    pub fn list_views(&self) -> Vec<String> {
        self.views.keys().cloned().collect()
    }

    pub fn get_view_definition(&self, view_name: &str) -> Option<String> {
        self.views.get(view_name).cloned()
    }
}

