use crate::db::Database;
use anyhow::Context;
use async_trait::async_trait;
use std::sync::Arc;
use tokio::sync::Mutex;
use tokio_postgres::{Client, NoTls};

/// PostgreSQL database adapter
pub struct PostgresDB {
    client: Arc<Mutex<Client>>,
}

#[allow(dead_code)]
impl PostgresDB {
    /// Create a new PostgreSQL adapter
    pub async fn new(conn_str: &str) -> anyhow::Result<Self> {
        let (client, connection) = tokio_postgres::connect(conn_str, NoTls)
            .await
            .context("Failed to connect to PostgreSQL")?;

        // Spawn connection driver
        tokio::spawn(async move {
            if let Err(e) = connection.await {
                tracing::error!("PostgreSQL connection error: {}", e);
            }
        });

        Ok(Self {
            client: Arc::new(Mutex::new(client)),
        })
    }

    /// Create a new PostgreSQL adapter with timeout
    pub async fn with_timeout(conn_str: &str, _timeout_secs: u64) -> anyhow::Result<Self> {
        let (client, connection) = tokio_postgres::connect(conn_str, NoTls)
            .await
            .context("Failed to connect to PostgreSQL")?;

        tokio::spawn(async move {
            if let Err(e) = connection.await {
                tracing::error!("PostgreSQL connection error: {}", e);
            }
        });

        Ok(Self {
            client: Arc::new(Mutex::new(client)),
        })
    }
}

#[async_trait]
impl Database for PostgresDB {
    async fn execute(&self, sql: &str) -> anyhow::Result<()> {
        let client = self.client.lock().await;
        client.execute(sql, &[]).await?;
        Ok(())
    }

    async fn read(&self, key: usize) -> anyhow::Result<()> {
        let client = self.client.lock().await;
        client
            .query("SELECT * FROM accounts WHERE id = $1", &[&(key as i32)])
            .await?;
        Ok(())
    }

    async fn update(&self, key: usize) -> anyhow::Result<()> {
        let client = self.client.lock().await;
        client
            .execute(
                "UPDATE accounts SET balance = balance + 1 WHERE id = $1",
                &[&(key as i32)],
            )
            .await?;
        Ok(())
    }

    async fn insert(&self, key: usize) -> anyhow::Result<()> {
        let client = self.client.lock().await;
        client
            .execute(
                "INSERT INTO accounts (id, balance) VALUES ($1, 100) ON CONFLICT DO NOTHING",
                &[&(key as i32)],
            )
            .await?;
        Ok(())
    }

    async fn scan(&self, start: usize, end: usize) -> anyhow::Result<()> {
        let client = self.client.lock().await;
        client
            .query(
                "SELECT * FROM accounts WHERE id BETWEEN $1 AND $2",
                &[&(start as i32), &(end as i32)],
            )
            .await?;
        Ok(())
    }
}

//! PostgreSQL Benchmark Runner
//!
//! Provides benchmark functionality for PostgreSQL with comparison support.

use crate::db::postgres::PostgresDB;
use crate::db::Database;
use crate::metrics::latency::LatencyRecorder;
use serde::{Deserialize, Serialize};

/// Benchmark result for a single database
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BenchmarkResult {
    /// Database name
    pub db_name: String,
    /// Total execution time in milliseconds
    pub total_time_ms: u64,
    /// Number of operations
    pub operations: u64,
    /// Queries per second
    pub qps: f64,
    /// Latency statistics in milliseconds
    pub latency_stats: LatencyStatsMs,
}

/// Latency statistics in milliseconds
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct LatencyStatsMs {
    /// 50th percentile in milliseconds
    pub p50_ms: f64,
    /// 95th percentile in milliseconds
    pub p95_ms: f64,
    /// 99th percentile in milliseconds
    pub p99_ms: f64,
}

impl Default for LatencyStatsMs {
    fn default() -> Self {
        Self {
            p50_ms: 0.0,
            p95_ms: 0.0,
            p99_ms: 0.0,
        }
    }
}

/// PostgreSQL benchmark runner
pub struct PostgresBenchmark {
    conn_str: String,
}

#[allow(dead_code)]
impl PostgresBenchmark {
    /// Create a new PostgreSQL benchmark runner
    pub fn new(conn_str: &str) -> Self {
        Self {
            conn_str: conn_str.to_string(),
        }
    }

    /// Run read benchmark
    pub async fn run_reads(&self, operations: u64) -> anyhow::Result<BenchmarkResult> {
        let pg = PostgresDB::new(&self.conn_str).await?;
        let latency_recorder = LatencyRecorder::new();
        let start = std::time::Instant::now();

        for i in 0..operations {
            let iteration_start = std::time::Instant::now();
            pg.read(i as usize).await?;
            latency_recorder.record(iteration_start.elapsed().as_micros() as u64);
        }

        let elapsed = start.elapsed().as_millis() as u64;
        let stats = latency_recorder.snapshot();

        Ok(BenchmarkResult {
            db_name: "postgres".to_string(),
            total_time_ms: elapsed,
            operations,
            qps: operations as f64 / (elapsed as f64 / 1000.0),
            latency_stats: LatencyStatsMs {
                p50_ms: stats.p50 as f64 / 1000.0,
                p95_ms: stats.p95 as f64 / 1000.0,
                p99_ms: stats.p99 as f64 / 1000.0,
            },
        })
    }

    /// Run update benchmark
    pub async fn run_updates(&self, operations: u64) -> anyhow::Result<BenchmarkResult> {
        let pg = PostgresDB::new(&self.conn_str).await?;
        let latency_recorder = LatencyRecorder::new();
        let start = std::time::Instant::now();

        for i in 0..operations {
            let iteration_start = std::time::Instant::now();
            pg.update(i as usize).await?;
            latency_recorder.record(iteration_start.elapsed().as_micros() as u64);
        }

        let elapsed = start.elapsed().as_millis() as u64;
        let stats = latency_recorder.snapshot();

        Ok(BenchmarkResult {
            db_name: "postgres".to_string(),
            total_time_ms: elapsed,
            operations,
            qps: operations as f64 / (elapsed as f64 / 1000.0),
            latency_stats: LatencyStatsMs {
                p50_ms: stats.p50 as f64 / 1000.0,
                p95_ms: stats.p95 as f64 / 1000.0,
                p99_ms: stats.p99 as f64 / 1000.0,
            },
        })
    }

    /// Run mixed workload benchmark
    pub async fn run_mixed(
        &self,
        operations: u64,
        read_ratio: f64,
    ) -> anyhow::Result<BenchmarkResult> {
        let pg = PostgresDB::new(&self.conn_str).await?;
        let latency_recorder = LatencyRecorder::new();
        let start = std::time::Instant::now();

        for i in 0..operations {
            let iteration_start = std::time::Instant::now();
            if (i as f64 / operations as f64) < read_ratio {
                pg.read(i as usize).await?;
            } else {
                pg.update(i as usize).await?;
            }
            latency_recorder.record(iteration_start.elapsed().as_micros() as u64);
        }

        let elapsed = start.elapsed().as_millis() as u64;
        let stats = latency_recorder.snapshot();

        Ok(BenchmarkResult {
            db_name: "postgres".to_string(),
            total_time_ms: elapsed,
            operations,
            qps: operations as f64 / (elapsed as f64 / 1000.0),
            latency_stats: LatencyStatsMs {
                p50_ms: stats.p50 as f64 / 1000.0,
                p95_ms: stats.p95 as f64 / 1000.0,
                p99_ms: stats.p99 as f64 / 1000.0,
            },
        })
    }
}

impl BenchmarkResult {
    #[allow(dead_code)]
    pub fn print(&self) {
        println!("=== {} Benchmark Results ===", self.db_name);
        println!("Total Time: {} ms", self.total_time_ms);
        println!("Operations: {}", self.operations);
        println!("QPS: {:.2}", self.qps);
