//! SQL data types for catalog definitions
//!
//! This module defines the data types that can be used in column definitions.
//! These are the logical types used in the catalog, separate from the
//! physical storage types in the Value enum.

use serde::{Deserialize, Serialize};
use std::fmt;

/// SQL data types supported by the database
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize, Default)]
pub enum DataType {
    /// NULL type
    Null,
    /// Boolean type (TRUE/FALSE)
    Boolean,
    /// 64-bit signed integer
    Integer,
    /// 64-bit floating point
    Float,
    /// Variable-length text
    #[default]
    Text,
    /// Binary large object
    Blob,
    /// Date type (days since epoch)
    Date,
    /// Timestamp type (microseconds since epoch)
    Timestamp,
}

impl DataType {
    /// Get the SQL name for this data type
    pub fn sql_name(&self) -> &'static str {
        match self {
            DataType::Null => "NULL",
            DataType::Boolean => "BOOLEAN",
            DataType::Integer => "INTEGER",
            DataType::Float => "FLOAT",
            DataType::Text => "TEXT",
            DataType::Blob => "BLOB",
            DataType::Date => "DATE",
            DataType::Timestamp => "TIMESTAMP",
        }
    }

    /// Parse a SQL type name into a DataType
    pub fn parse_sql_name(name: &str) -> Option<Self> {
        match name.to_uppercase().as_str() {
            "NULL" => Some(DataType::Null),
            "BOOLEAN" | "BOOL" => Some(DataType::Boolean),
            "INTEGER" | "INT" | "INT64" | "BIGINT" => Some(DataType::Integer),
            "FLOAT" | "DOUBLE" | "REAL" => Some(DataType::Float),
            "TEXT" | "VARCHAR" | "CHAR" | "STRING" => Some(DataType::Text),
            "BLOB" | "BINARY" | "VARBINARY" => Some(DataType::Blob),
            "DATE" => Some(DataType::Date),
            "TIMESTAMP" | "DATETIME" => Some(DataType::Timestamp),
            _ => None,
        }
    }

    /// Check if this type can be used in a primary key
    pub fn is_valid_for_primary_key(&self) -> bool {
        matches!(
            self,
            DataType::Integer | DataType::Text | DataType::Boolean | DataType::Date
        )
    }

    /// Check if this type supports ordering comparisons
    pub fn is_orderable(&self) -> bool {
        !matches!(self, DataType::Blob)
    }

    /// Check if this type supports equality comparisons
    pub fn is_equatable(&self) -> bool {
        true
    }
}

impl fmt::Display for DataType {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{}", self.sql_name())
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_data_type_sql_name() {
        assert_eq!(DataType::Integer.sql_name(), "INTEGER");
        assert_eq!(DataType::Text.sql_name(), "TEXT");
        assert_eq!(DataType::Boolean.sql_name(), "BOOLEAN");
    }

    #[test]
    fn test_parse_sql_name() {
        assert_eq!(DataType::parse_sql_name("INTEGER"), Some(DataType::Integer));
        assert_eq!(DataType::parse_sql_name("INT"), Some(DataType::Integer));
        assert_eq!(DataType::parse_sql_name("VARCHAR"), Some(DataType::Text));
        assert_eq!(DataType::parse_sql_name("BLOB"), Some(DataType::Blob));
        assert_eq!(DataType::parse_sql_name("UNKNOWN"), None);
    }

    #[test]
    fn test_valid_for_primary_key() {
        assert!(DataType::Integer.is_valid_for_primary_key());
        assert!(DataType::Text.is_valid_for_primary_key());
        assert!(!DataType::Blob.is_valid_for_primary_key());
        assert!(!DataType::Float.is_valid_for_primary_key());
    }

    #[test]
    fn test_is_orderable() {
        assert!(DataType::Integer.is_orderable());
        assert!(DataType::Text.is_orderable());
        assert!(!DataType::Blob.is_orderable());
    }

    #[test]
    fn test_default() {
        assert_eq!(DataType::default(), DataType::Text);
    }

    #[test]
    fn test_display() {
        assert_eq!(format!("{}", DataType::Integer), "INTEGER");
        assert_eq!(format!("{}", DataType::Text), "TEXT");
    }
}

//! Catalog error types

use thiserror::Error;

/// Catalog-specific errors
#[derive(Error, Debug)]
pub enum CatalogError {
    /// Schema not found
    #[error("Schema '{0}' not found")]
    SchemaNotFound(String),

    /// Table not found
    #[error("Table '{table}' not found in schema '{schema}'")]
    TableNotFound { schema: String, table: String },

    /// Column not found
    #[error("Column '{column}' not found in table '{schema}.{table}'")]
    ColumnNotFound {
        schema: String,
        table: String,
        column: String,
    },

    /// Duplicate schema name
    #[error("Schema '{0}' already exists")]
    DuplicateSchema(String),

    /// Duplicate table name
    #[error("Table '{table}' already exists in schema '{schema}'")]
    DuplicateTable { schema: String, table: String },

    /// Duplicate column name
    #[error("Column '{column}' already exists in table '{schema}.{table}'")]
    DuplicateColumn {
        schema: String,
        table: String,
        column: String,
    },

    /// Invalid primary key
    #[error("Invalid primary key: {0}")]
    InvalidPrimaryKey(String),

    /// Foreign key reference failed
    #[error(
        "Foreign key reference to '{referenced}' in table '{schema}.{table}' failed: {reason}"
    )]
    ForeignKeyViolation {
        schema: String,
        table: String,
        column: String,
        referenced: String,
        reason: String,
    },

    /// Cyclic foreign key dependency detected
    #[error("Cyclic foreign key dependency detected involving table '{0}'")]
    CyclicDependency(String),

    /// Invariant violation
    #[error("Catalog invariant violation: {0}")]
    InvariantViolation(String),

    /// Serialization/deserialization error
    #[error("Serialization error: {0}")]
    SerializationError(String),
}

/// Result type for catalog operations
pub type CatalogResult<T> = Result<T, CatalogError>;

//! Index information for catalog tables

use serde::{Deserialize, Serialize};

/// Index type
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum IndexType {
    /// B+ Tree index (default)
    BTree,
    /// Hash index
    Hash,
    /// Full-text search index
    FullText,
}

/// Index information for a table index
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct IndexInfo {
    /// Index name (unique within schema)
    pub name: String,
    /// Table name this index belongs to
    pub table_name: String,
    /// Column names that make up the index
    pub columns: Vec<String>,
    /// Index type
    pub index_type: IndexType,
    /// Whether the index is unique
    pub is_unique: bool,
    /// Whether the index is the primary key index
    pub is_primary_key: bool,
}

impl IndexInfo {
    /// Create a new index info
    pub fn new(
        name: impl Into<String>,
        table_name: impl Into<String>,
        columns: Vec<String>,
    ) -> Self {
        Self {
            name: name.into(),
            table_name: table_name.into(),
            columns,
            index_type: IndexType::BTree,
            is_unique: false,
            is_primary_key: false,
        }
    }

    /// Set as primary key index
    pub fn primary_key(mut self) -> Self {
        self.is_primary_key = true;
        self.is_unique = true;
        self
    }

    /// Set as unique index
    pub fn unique(mut self) -> Self {
        self.is_unique = true;
        self
    }

    /// Set the index type
    pub fn with_type(mut self, index_type: IndexType) -> Self {
        self.index_type = index_type;
        self
    }
}

