//! Latency Statistics Module
//!
//! Provides percentile-based latency statistics (P50/P95/P99) for benchmark results.

use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct LatencyStats {
    samples: Vec<u64>,
    sorted: bool,
}

impl LatencyStats {
    pub fn new() -> Self {
        Self {
            samples: Vec::new(),
            sorted: false,
        }
    }

    pub fn with_capacity(capacity: usize) -> Self {
        Self {
            samples: Vec::with_capacity(capacity),
            sorted: false,
        }
    }

    pub fn record(&mut self, latency_us: u64) {
        self.samples.push(latency_us);
        self.sorted = false;
    }

    pub fn record_batch(&mut self, latencies: impl IntoIterator<Item = u64>) {
        self.samples.extend(latencies);
        self.sorted = false;
    }

    #[allow(dead_code)]
    fn sort(&mut self) {
        if !self.sorted {
            self.samples.sort();
            self.sorted = true;
        }
    }

    fn percentile(&self, p: f64) -> u64 {
        if self.samples.is_empty() {
            return 0;
        }
        // Must sort first for accurate percentile
        let mut sorted = self.samples.clone();
        sorted.sort();
        if sorted.len() == 1 {
            return sorted[0];
        }

        let idx = ((sorted.len() - 1) as f64 * p) as usize;
        sorted[idx.min(sorted.len() - 1)]
    }

    pub fn count(&self) -> usize {
        self.samples.len()
    }

    pub fn min(&self) -> Option<u64> {
        self.samples.iter().min().copied()
    }

    pub fn max(&self) -> Option<u64> {
        self.samples.iter().max().copied()
    }

    pub fn sum(&self) -> u64 {
        self.samples.iter().sum()
    }

    pub fn avg(&self) -> f64 {
        if self.samples.is_empty() {
            return 0.0;
        }
        self.sum() as f64 / self.samples.len() as f64
    }

    pub fn p50(&self) -> u64 {
        self.percentile(0.50)
    }

    pub fn p95(&self) -> u64 {
        self.percentile(0.95)
    }

    pub fn p99(&self) -> u64 {
        self.percentile(0.99)
    }

    pub fn p999(&self) -> u64 {
        self.percentile(0.999)
    }

    pub fn median(&self) -> u64 {
        self.p50()
    }
}

impl Default for LatencyStats {
    fn default() -> Self {
        Self::new()
    }
}

