    use super::*;

    #[test]
    fn test_network_metrics_creation() {
        let metrics = NetworkMetrics::new();
        assert_eq!(metrics.connections_active(), 0);
    }

    #[test]
    fn test_network_metrics_connection_open() {
        let metrics = NetworkMetrics::new();
