        shard.add_replica(2);
        shard.add_replica(3);
        manager.create_shard(shard);

        let info = manager.get_shard(0).unwrap();
        assert_eq!(info.replica_nodes, vec![1, 2, 3]);
    }

    #[test]
    fn test_partition_rule() {
