        // Sort both inputs by join key
        self.left_sorted.sort_by(|a, b| compare_join_keys(a, b));
        self.right_sorted.sort_by(|a, b| compare_join_keys(a, b));

        // Reset indices
        self.left_idx = 0;
        self.right_idx = 0;
        self.left_matches.clear();
        self.left_match_idx = 0;
