impl NestedLoopJoinVolcanoExecutor {
    pub fn new(
        left: Box<dyn VolcanoExecutor>,
        right: Box<dyn VolcanoExecutor>,
        join_type: sqlrustgo_planner::JoinType,
        left_schema: Schema,
        right_schema: Schema,
