        assert_eq!(output.lines[2].operator, "Projection");
        assert_eq!(output.lines[2].indent, 0);
    }

    #[test]
    fn test_explain_analyze_collects_timing() {
        let scan = create_test_seq_scan();
        let output = explain_analyze(&scan);

        // Should have timing information
        assert!(output.total_time_us.is_some());
        assert!(output.lines[0].execution_time_us.is_some());
    }

    #[test]
    fn test_explain_output_format_tree() {
        let scan = create_test_seq_scan();
        let output = explain(&scan);

        let tree = output.to_string_tree();

        // Check that tree format contains expected parts
        assert!(tree.contains("-> SeqScan"));
        assert!(tree.contains("table=users"));
        assert!(tree.contains("estimated_rows="));
    }

    #[test]
    fn test_explain_with_limit() {
        let input_schema = Schema::new(vec![Field::new(
            "id".to_string(),
            sqlrustgo_planner::DataType::Integer,
        )]);
        let scan = Box::new(SeqScanExec::new("users".to_string(), input_schema));
        let limit = LimitExec::new(scan, 10, Some(5));

        let output = explain(&limit);

        // Should have 2 lines: SeqScan, Limit
        assert_eq!(output.lines.len(), 2);
        let limit_line = &output.lines[1];
        assert_eq!(limit_line.operator, "Limit");
        assert!(limit_line.details.iter().any(|d| d.contains("limit=10")));
        assert!(limit_line.details.iter().any(|d| d.contains("offset=5")));
    }
}

//! Filter Executor - Volcano Model implementation for filter operations
//!
//! This module provides the FilterVolcanoExecutor which implements the VolcanoExecutor trait
//! for filtering rows based on a predicate expression.

use sqlrustgo_planner::{Expr, Schema};
use sqlrustgo_types::{SqlResult, Value};
use std::any::Any;

use super::VolcanoExecutor;

/// FilterVolcanoExecutor - executes filter (WHERE) operations
///
/// This executor takes a child executor and a predicate expression.
/// It only returns rows where the predicate evaluates to true.
pub struct FilterVolcanoExecutor {
    child: Box<dyn VolcanoExecutor>,
    predicate: Expr,
    schema: Schema,
    input_schema: Schema,
    initialized: bool,
}

impl FilterVolcanoExecutor {
    /// Create a new FilterVolcanoExecutor
    pub fn new(
        child: Box<dyn VolcanoExecutor>,
        predicate: Expr,
        schema: Schema,
        input_schema: Schema,
    ) -> Self {
        Self {
            child,
            predicate,
            schema,
            input_schema,
            initialized: false,
        }
    }

    /// Get the predicate expression
    pub fn predicate(&self) -> &Expr {
        &self.predicate
    }

    /// Get the input schema
    pub fn input_schema(&self) -> &Schema {
        &self.input_schema
    }
}

impl VolcanoExecutor for FilterVolcanoExecutor {
    fn init(&mut self) -> SqlResult<()> {
        self.child.init()?;
        self.initialized = true;
        Ok(())
    }

    fn next(&mut self) -> SqlResult<Option<Vec<Value>>> {
        // Pull-based iteration: keep asking child for next row until predicate matches
        while let Some(row) = self.child.next()? {
            let predicate_val = self
                .predicate
                .evaluate(&row, &self.input_schema)
                .unwrap_or(Value::Null);

            // Only return rows where predicate evaluates to Boolean(true)
            if let Value::Boolean(true) = predicate_val {
                return Ok(Some(row));
            }
            // Otherwise continue to next row
        }
        // No more rows or no matching rows
        Ok(None)
    }

    fn close(&mut self) -> SqlResult<()> {
        self.child.close()?;
        self.initialized = false;
        Ok(())
    }

    fn schema(&self) -> &Schema {
        &self.schema
    }

    fn name(&self) -> &str {
        "Filter"
    }

    fn is_initialized(&self) -> bool {
        self.initialized
    }

    fn as_any(&self) -> &dyn Any {
        self
    }
}

