        let mut left_storage = MemoryStorage::new();
        left_storage
            .insert(
                "left_table",
                vec![
                    vec![Value::Integer(1), Value::Text("A".to_string())],
                    vec![Value::Integer(2), Value::Text("B".to_string())],
