        profiler.record("SeqScan", "scan", 1000, 100, 1);
        profiler.record("HashJoin", "join", 2000, 50, 1);

        let report = profiler.generate_report();
        assert!(report.contains("SQLRustGo"));
        assert!(report.contains("SeqScan"));
    }

    #[test]
    fn test_profile_timer() {
        let mut profile = OperatorProfile::new("Test", "test");

        {
            let _timer = ProfileTimer::new(&mut profile, 100, 5);
            std::thread::sleep(Duration::from_millis(1));
        }

        assert_eq!(profile.execution_count, 1);
        assert!(profile.total_time_ns > 0);
    }

    #[test]
    fn test_global_profile_timer() {
        let profiler = Profiler::new();

        // Ensure profile exists (without recording an execution)
        let _ = profiler.get_operator_profile("TestOp", "test");

        {
            let _timer = profiler.start_timer("TestOp", 100, 5);
            std::thread::sleep(Duration::from_millis(1));
        }

        let profiles = profiler.get_all_profiles();
        let test_op = profiles
            .iter()
            .find(|p| p.operator_name == "TestOp")
            .unwrap();
        assert_eq!(test_op.execution_count, 1);
        assert!(test_op.total_time_ns > 0);
    }

    #[test]
    fn test_start_timer_creates_profile() {
        let profiler = Profiler::new();

        // start_timer should create profile if it doesn't exist
        {
            let _timer = profiler.start_timer("NewOp", 50, 2);
            std::thread::sleep(Duration::from_millis(1));
        }

        let profiles = profiler.get_all_profiles();
        let new_op = profiles
            .iter()
            .find(|p| p.operator_name == "NewOp")
            .unwrap();
        assert_eq!(new_op.execution_count, 1);
    }
}

//! ParallelExecutor Module
//!
//! Provides parallel execution wrapper for VolcanoExecutor.

use crate::operator_profile::GLOBAL_PROFILER;
use crate::task_scheduler::{RayonTaskScheduler, TaskScheduler};
use crate::ExecutorResult;
use sqlrustgo_planner::{HashJoinExec, JoinType, PhysicalPlan};
use sqlrustgo_storage::StorageEngine;
use sqlrustgo_types::{SqlResult, Value};
use std::sync::Arc;
use std::time::Instant;

/// ParallelExecutor trait - unified interface for parallel execution
pub trait ParallelExecutor: Send + Sync {
    /// Execute a plan in parallel
    fn execute_parallel(&self, plan: &dyn PhysicalPlan) -> SqlResult<ExecutorResult>;

    /// Set parallel degree
    fn set_parallel_degree(&mut self, degree: usize);

    /// Get current parallel degree
    fn parallel_degree(&self) -> usize;
}

/// ParallelVolcanoExecutor - wrapper for VolcanoExecutor with parallel execution
pub struct ParallelVolcanoExecutor {
    storage: Arc<dyn StorageEngine>,
    scheduler: Arc<RayonTaskScheduler>,
    parallel_degree: usize,
}

impl ParallelVolcanoExecutor {
    /// Create a new ParallelVolcanoExecutor with memory storage and default scheduler
    pub fn new() -> Self {
        let storage: Arc<dyn StorageEngine> = Arc::new(sqlrustgo_storage::MemoryStorage::new());
        let scheduler = RayonTaskScheduler::new(
            std::thread::available_parallelism()
                .map(|n| n.get())
                .unwrap_or(4),
        );
        let parallel_degree = scheduler.current_parallelism();
        Self {
            storage,
            scheduler: Arc::new(scheduler),
            parallel_degree,
        }
    }

    /// Create with custom storage and scheduler
    pub fn with_storage_and_scheduler(
        storage: Arc<dyn StorageEngine>,
        scheduler: Arc<RayonTaskScheduler>,
    ) -> Self {
        let parallel_degree = scheduler.current_parallelism();
        Self {
            storage,
            scheduler,
            parallel_degree,
        }
    }

    /// Create with custom scheduler
    pub fn with_scheduler(scheduler: Arc<RayonTaskScheduler>) -> Self {
        let storage: Arc<dyn StorageEngine> = Arc::new(sqlrustgo_storage::MemoryStorage::new());
        let parallel_degree = scheduler.current_parallelism();
        Self {
            storage,
            scheduler,
            parallel_degree,
        }
    }

    /// Create with custom scheduler and parallel degree
    pub fn with_config(scheduler: Arc<RayonTaskScheduler>, parallel_degree: usize) -> Self {
        let storage: Arc<dyn StorageEngine> = Arc::new(sqlrustgo_storage::MemoryStorage::new());
        Self {
            storage,
            scheduler,
            parallel_degree,
        }
    }

    /// Create with storage and parallel degree
    pub fn with_storage(storage: Arc<dyn StorageEngine>, parallel_degree: usize) -> Self {
        let scheduler = RayonTaskScheduler::new(parallel_degree);
        Self {
            storage,
            scheduler: Arc::new(scheduler),
            parallel_degree,
        }
    }

    /// Get the scheduler
    pub fn scheduler(&self) -> &Arc<RayonTaskScheduler> {
        &self.scheduler
    }

    /// Get parallel degree
    pub fn degree(&self) -> usize {
        self.parallel_degree
    }

    /// Get the storage engine
    pub fn storage(&self) -> &Arc<dyn StorageEngine> {
        &self.storage
    }
}

impl Default for ParallelVolcanoExecutor {
    fn default() -> Self {
        Self::new()
    }
}

impl ParallelExecutor for ParallelVolcanoExecutor {
    fn execute_parallel(&self, plan: &dyn PhysicalPlan) -> SqlResult<ExecutorResult> {
        match plan.name() {
            "SeqScan" => self.execute_parallel_scan(plan),
            "HashJoin" => self.execute_parallel_hash_join(plan),
            "Aggregate" => self.execute_parallel_aggregate(plan),
            "Filter" => self.execute_parallel_filter(plan),
            "Projection" => self.execute_parallel_projection(plan),
            "Count" => self.execute_parallel_count(plan),
            _ => self.execute_fallback(plan),
        }
    }

    fn set_parallel_degree(&mut self, degree: usize) {
        self.parallel_degree = degree.max(1);
    }

    fn parallel_degree(&self) -> usize {
        self.parallel_degree
    }
}

impl ParallelVolcanoExecutor {
    /// Execute parallel sequential scan using efficient partitioning
    fn execute_parallel_scan(&self, plan: &dyn PhysicalPlan) -> SqlResult<ExecutorResult> {
        let table_name = plan.table_name();
        if table_name.is_empty() {
            return Ok(ExecutorResult::empty());
        }

        let start = Instant::now();
        let degree = self.parallel_degree;

        // Single scan to get all data
        let all_data = self.storage.scan(table_name)?;

        if all_data.is_empty() {
            return Ok(ExecutorResult::empty());
        }

        let total_count = all_data.len();

        // For small datasets or single thread, fall back to sequential
        // to avoid parallelization overhead
        if total_count < 100_000 || degree <= 1 {
            let duration = start.elapsed();
            GLOBAL_PROFILER.record(
                "ParallelSeqScan",
                "sequential_scan",
                duration.as_nanos() as u64,
                total_count,
                1,
            );
            return Ok(ExecutorResult::new(all_data, 0));
        }

        // Pre-calculate partition boundaries
        let base_size = total_count / degree;
        let remainder = total_count % degree;
        let mut partitions: Vec<(usize, usize)> = Vec::with_capacity(degree);
        let mut current = 0;
        for i in 0..degree {
            let size = if i < remainder {
                base_size + 1
            } else {
                base_size
            };
            if size > 0 {
                partitions.push((current, current + size));
            }
            current += size;
        }

        // Use rayon to clone partitions in parallel
        use rayon::iter::{IntoParallelIterator, ParallelIterator};
        let partition_results: Vec<Vec<Vec<Value>>> = partitions
            .into_par_iter()
            .map(|(start_idx, end_idx)| all_data[start_idx..end_idx].to_vec())
            .collect();

        // Flatten results into single vector
        let mut all_rows: Vec<Vec<Value>> = Vec::with_capacity(total_count);
        for mut partition in partition_results {
            all_rows.append(&mut partition);
        }

        let row_count = all_rows.len();
        let duration = start.elapsed();

        GLOBAL_PROFILER.record(
            "ParallelSeqScan",
            "parallel_scan",
            duration.as_nanos() as u64,
            row_count,
            degree,
        );

        Ok(ExecutorResult::new(all_rows, 0))
    }

    /// Execute parallel hash join by partitioning
    fn execute_parallel_hash_join(&self, plan: &dyn PhysicalPlan) -> SqlResult<ExecutorResult> {
        let children = plan.children();
        if children.len() < 2 {
            return Ok(ExecutorResult::empty());
        }

        let start = Instant::now();
        let degree = self.parallel_degree;

        // Execute left and right children in parallel using rayon
        let (left_rows, right_rows) = rayon::join(
            || self.execute_child(children[0]),
            || self.execute_child(children[1]),
        );

        let left_result = left_rows?;
        let right_result = right_rows?;

        let hash_join = plan.as_any().downcast_ref::<HashJoinExec>();

        let (join_type, condition) = match hash_join {
            Some(hj) => (hj.join_type(), hj.condition().cloned()),
            None => return Ok(ExecutorResult::empty()),
        };

        let left_schema = children[0].schema();
        let right_schema = children[1].schema();

        // If no condition, return cartesian product
        let condition = match condition {
            Some(c) => c,
            None => {
                let results = Self::cartesian_product(&left_result.rows, &right_result.rows);
                let row_count = results.len();
                let duration = start.elapsed();
                GLOBAL_PROFILER.record(
                    "ParallelHashJoin",
                    "join",
                    duration.as_nanos() as u64,
                    row_count,
                    degree,
                );
                return Ok(ExecutorResult::new(results, 0));
            }
        };

        // Partition-based parallel join
        let results = self.partition_hash_join(
            &left_result.rows,
            &right_result.rows,
            &condition,
            left_schema,
            right_schema,
            join_type,
        );

        let row_count = results.len();
        let duration = start.elapsed();

        GLOBAL_PROFILER.record(
            "ParallelHashJoin",
            "join",
            duration.as_nanos() as u64,
            row_count,
            degree,
        );

        Ok(ExecutorResult::new(results, 0))
    }

    /// Execute a child plan (helper for parallel execution)
    fn execute_child(&self, plan: &dyn PhysicalPlan) -> SqlResult<ExecutorResult> {
        // For now, use simple sequential execution for child plans
        // In a full implementation, this would also be parallelized
        match plan.name() {
            "SeqScan" => {
                let table_name = plan.table_name();
                if table_name.is_empty() {
                    return Ok(ExecutorResult::empty());
                }
                let records = self.storage.scan(table_name).unwrap_or_default();
                Ok(ExecutorResult::new(records, 0))
            }
            _ => Ok(ExecutorResult::empty()),
        }
    }

    /// Partition-based hash join for parallel execution
    fn partition_hash_join(
        &self,
        left: &[Vec<Value>],
        right: &[Vec<Value>],
        condition: &sqlrustgo_planner::Expr,
        left_schema: &sqlrustgo_planner::Schema,
        right_schema: &sqlrustgo_planner::Schema,
        join_type: JoinType,
    ) -> Vec<Vec<Value>> {
        if left.is_empty() || right.is_empty() {
            return match join_type {
                JoinType::Left | JoinType::LeftSemi | JoinType::LeftAnti => left.to_vec(),
                _ => vec![],
            };
        }

        match join_type {
            JoinType::Inner => {
                self.partition_hash_inner_join(left, right, condition, left_schema, right_schema)
            }
            JoinType::Left => {
                let matched = self.partition_hash_inner_join(
                    left,
                    right,
                    condition,
                    left_schema,
                    right_schema,
                );
                self.extend_with_left_unmatched(left, &matched)
            }
            _ => {
                // Fallback to single-threaded for other join types
                Self::hash_inner_join_fallback(left, right, condition, left_schema, right_schema)
            }
        }
    }

    /// Parallel hash inner join using partition and conquer
    fn partition_hash_inner_join(
        &self,
        left: &[Vec<Value>],
        right: &[Vec<Value>],
        condition: &sqlrustgo_planner::Expr,
        left_schema: &sqlrustgo_planner::Schema,
        right_schema: &sqlrustgo_planner::Schema,
    ) -> Vec<Vec<Value>> {
        let degree = self.parallel_degree;

        // Partition right side into buckets for parallel processing
        let right_buckets: Vec<Vec<&Vec<Value>>> = (0..degree)
            .map(|bucket_idx| {
                right
                    .iter()
                    .enumerate()
                    .filter(|(idx, _)| idx % degree == bucket_idx)
                    .map(|(_, row)| row)
                    .collect()
            })
            .collect();

        // Process each bucket in parallel
        let results: Vec<Vec<Vec<Value>>> = right_buckets
            .into_iter()
            .map(|bucket| {
                let mut bucket_results = Vec::new();
                for right_row in bucket {
                    for left_row in left {
                        if Self::evaluate_join_condition(
                            left_row,
                            right_row,
                            condition,
                            left_schema,
                            right_schema,
                        ) {
                            let mut combined = left_row.clone();
                            combined.extend(right_row.iter().cloned());
                            bucket_results.push(combined);
                        }
                    }
                }
                bucket_results
            })
            .collect();

        results.into_iter().flatten().collect()
    }

    /// Extend matched results with unmatched left rows for LEFT JOIN
    fn extend_with_left_unmatched(
        &self,
        left: &[Vec<Value>],
        matched: &[Vec<Value>],
    ) -> Vec<Vec<Value>> {
        let mut results = matched.to_vec();

        // Find unmatched left rows
        for left_row in left {
            let left_len = left_row.len();
            let is_matched = matched.iter().any(|m| {
                m.iter().take(left_len).collect::<Vec<_>>() == left_row.iter().collect::<Vec<_>>()
            });
            if !is_matched {
                let mut combined = left_row.clone();
                // Add NULLs for right side
                combined.extend(std::iter::repeat_n(
                    Value::Null,
                    matched.first().map(|m| m.len() - left_len).unwrap_or(0),
                ));
                results.push(combined);
            }
        }

        results
    }

    /// Evaluate join condition between two rows
    fn evaluate_join_condition(
        left: &[Value],
        right: &[Value],
        condition: &sqlrustgo_planner::Expr,
        left_schema: &sqlrustgo_planner::Schema,
        right_schema: &sqlrustgo_planner::Schema,
    ) -> bool {
        if let sqlrustgo_planner::Expr::BinaryExpr {
            left: l,
            op,
            right: r,
        } = condition
        {
            let left_val = l.evaluate(left, left_schema);
            let right_val = r.evaluate(right, right_schema);
            match (left_val, right_val, op) {
                (Some(v1), Some(v2), sqlrustgo_planner::Operator::Eq) => v1 == v2,
                _ => false,
            }
        } else {
            false
        }
    }

    /// Fallback single-threaded execution
    fn execute_fallback(&self, _plan: &dyn PhysicalPlan) -> SqlResult<ExecutorResult> {
        // For plans we don't yet parallelize, return empty
        // In production, this would delegate to the VolcanoExecutor
        Ok(ExecutorResult::empty())
    }

    /// Execute parallel filter
    fn execute_parallel_filter(&self, _plan: &dyn PhysicalPlan) -> SqlResult<ExecutorResult> {
        // Filter is usually not the bottleneck, return empty for now
        Ok(ExecutorResult::empty())
    }

    /// Execute parallel projection
    fn execute_parallel_projection(&self, _plan: &dyn PhysicalPlan) -> SqlResult<ExecutorResult> {
        // Projection is usually not the bottleneck, return empty for now
        Ok(ExecutorResult::empty())
    }

    /// Execute parallel aggregate
    fn execute_parallel_aggregate(&self, _plan: &dyn PhysicalPlan) -> SqlResult<ExecutorResult> {
        // Aggregate can benefit from parallel execution
        // For now, return empty
        Ok(ExecutorResult::empty())
    }

    /// Execute parallel COUNT(*) using atomic counters
    /// This is much more efficient than scanning and cloning all rows
    fn execute_parallel_count(&self, plan: &dyn PhysicalPlan) -> SqlResult<ExecutorResult> {
        let table_name = plan.table_name();
        if table_name.is_empty() {
            return Ok(ExecutorResult::new(vec![vec![Value::Integer(0)]], 0));
        }

        let start = Instant::now();
        let degree = self.parallel_degree;

        // Single scan to get all data
        let all_data = self.storage.scan(table_name)?;

        let total_count = all_data.len();

        // For small datasets or single thread, fall back to sequential
        if total_count < 100_000 || degree <= 1 {
            let duration = start.elapsed();
            GLOBAL_PROFILER.record(
                "ParallelCount",
                "sequential_count",
                duration.as_nanos() as u64,
                total_count,
                1,
            );
            return Ok(ExecutorResult::new(
                vec![vec![Value::Integer(total_count as i64)]],
                0,
            ));
        }

        // Use atomic counters for parallel counting
        use rayon::iter::{IntoParallelIterator, ParallelIterator};
        use std::sync::atomic::{AtomicUsize, Ordering};

        let counter = AtomicUsize::new(0);

        // Pre-calculate partition boundaries
        let base_size = total_count / degree;
        let remainder = total_count % degree;
        let mut partitions: Vec<(usize, usize)> = Vec::with_capacity(degree);
        let mut current = 0;
        for i in 0..degree {
            let size = if i < remainder {
                base_size + 1
            } else {
                base_size
            };
            if size > 0 {
                partitions.push((current, current + size));
            }
            current += size;
        }

        // Count in parallel using atomic counters - no data cloning needed
        partitions.into_par_iter().for_each(|(start_idx, end_idx)| {
            let local_count = end_idx - start_idx;
            counter.fetch_add(local_count, Ordering::Relaxed);
        });

        let count = counter.load(Ordering::Relaxed) as i64;
        let duration = start.elapsed();

        GLOBAL_PROFILER.record(
            "ParallelCount",
            "parallel_count",
            duration.as_nanos() as u64,
            count as usize,
            degree,
        );

        Ok(ExecutorResult::new(vec![vec![Value::Integer(count)]], 0))
    }

    /// Compute cartesian product of two row sets
    fn cartesian_product(left: &[Vec<Value>], right: &[Vec<Value>]) -> Vec<Vec<Value>> {
        let mut results = Vec::new();
        for lrow in left {
            for rrow in right {
                let mut combined = lrow.clone();
                combined.extend(rrow.iter().cloned());
                results.push(combined);
            }
        }
        results
    }

    /// Fallback hash inner join (single-threaded)
    fn hash_inner_join_fallback(
        left: &[Vec<Value>],
        right: &[Vec<Value>],
        condition: &sqlrustgo_planner::Expr,
        left_schema: &sqlrustgo_planner::Schema,
        right_schema: &sqlrustgo_planner::Schema,
    ) -> Vec<Vec<Value>> {
        let mut results = Vec::new();
        for lrow in left {
            for rrow in right {
                if Self::evaluate_join_condition(lrow, rrow, condition, left_schema, right_schema) {
                    let mut combined = lrow.clone();
                    combined.extend(rrow.iter().cloned());
                    results.push(combined);
                }
            }
        }
        results
    }
}

