//! SQL Lexer implementation
//! Tokenizes SQL input strings into tokens

use crate::token::Token;

/// SQL Lexer - Tokenizer
///
/// # What (是什么)
/// Lexer 将原始 SQL 字符串分解为 Token 序列，是编译器的第一阶段
///
/// # Why (为什么)
/// Parser 需要结构化的 Token 而不是原始字符串，Lexer 负责这项转换工作
///
/// # How (如何实现)
/// - 逐字符扫描输入
/// - 识别关键字、标识符、字面量、运算符
/// - 跳过空白字符
/// - 使用有限状态机处理不同 token 类型
pub struct Lexer<'a> {
    input: &'a str,
    position: usize,
}

impl<'a> Lexer<'a> {
    /// Create a new lexer for the given input
    pub fn new(input: &'a str) -> Self {
        Self { input, position: 0 }
    }

    /// Get the current position in the input
    pub fn position(&self) -> usize {
        self.position
    }

    /// Check if we've reached the end of input
    fn is_eof(&self) -> bool {
        self.position >= self.input.len()
    }

    /// Get the current character without advancing
    fn peek_char(&self) -> char {
        self.input.chars().nth(self.position).unwrap_or('\0')
    }

    /// Get the current character and advance
    #[allow(dead_code)]
    fn next_char(&mut self) -> char {
        let ch = self.peek_char();
        self.position += 1;
        ch
    }

    /// Skip whitespace and comments
    fn skip_whitespace(&mut self) {
        while !self.is_eof() {
            let ch = self.peek_char();

            // Skip whitespace
            if ch.is_whitespace() {
                self.position += 1;
                continue;
            }

            // Skip single-line comments: --
            if ch == '-' && self.input[self.position..].starts_with("--") {
                while !self.is_eof() && self.peek_char() != '\n' {
                    self.position += 1;
                }
                continue;
            }

            // Skip block comments: /* ... */
            if ch == '/' && self.input[self.position..].starts_with("/*") {
                self.position += 2; // skip /*
                while !self.is_eof() && !self.input[self.position..].starts_with("*/") {
                    self.position += 1;
                }
                if !self.is_eof() {
                    self.position += 2; // skip */
                }
                continue;
            }

            break;
        }
    }

    /// Read a sequence of alphanumeric characters (for identifiers)
    fn read_identifier(&mut self) -> String {
        let start = self.position;
        while !self.is_eof() {
            let ch = self.peek_char();
            if !ch.is_alphanumeric() && ch != '_' {
                break;
            }
            self.position += 1;
        }
        self.input[start..self.position].to_string()
    }

    /// Read a number literal
    fn read_number(&mut self) -> String {
        let start = self.position;
        let mut has_decimal = false;
        while !self.is_eof() {
            let ch = self.peek_char();
            if ch == '.' {
                if has_decimal {
                    break;
                }
                has_decimal = true;
            } else if !ch.is_ascii_digit() {
                break;
            }
            self.position += 1;
        }
        self.input[start..self.position].to_string()
    }

    /// Read a string literal (single-quoted)
    fn read_string(&mut self) -> String {
        self.position += 1; // Skip opening quote
        let start = self.position;

        while !self.is_eof() {
            let ch = self.peek_char();
            if ch == '\'' {
                if self.input[self.position..].starts_with("''") {
                    self.position += 2;
                    continue;
                }
                break;
            }
            self.position += 1;
        }

        let result = self.input[start..self.position].to_string();
        if !self.is_eof() {
            self.position += 1; // Skip closing quote
        }
        result
    }

    /// Get the next token from the input
    pub fn next_token(&mut self) -> Token {
        self.skip_whitespace();

        if self.is_eof() {
            return Token::Eof;
        }

        let ch = self.peek_char();

        match ch {
            '(' => {
                self.position += 1;
                Token::LParen
            }
            ')' => {
                self.position += 1;
                Token::RParen
            }
            ',' => {
                self.position += 1;
                Token::Comma
            }
            ';' => {
                self.position += 1;
                Token::Semicolon
            }
            '*' => {
                self.position += 1;
                Token::Star
            }
            '+' => {
                self.position += 1;
                Token::Plus
            }
            '-' => {
                self.position += 1;
                Token::Minus
            }
            '/' => {
                self.position += 1;
                Token::Slash
            }
            '%' => {
                self.position += 1;
                Token::Percent
            }
            '.' => {
                self.position += 1;
                Token::Dot
            }
            ':' => {
                self.position += 1;
                Token::Colon
            }
            '\'' => Token::StringLiteral(self.read_string()),
            '?' => {
                self.position += 1;
                Token::QuestionMark
            }
            '=' => {
                self.position += 1;
                Token::Equal
            }
            '!' => {
                if self.input[self.position..].starts_with("!=") {
                    self.position += 2;
                    Token::NotEqual
                } else {
                    self.position += 1;
                    Token::Not
                }
            }
            '>' => {
                if self.input[self.position..].starts_with(">=") {
                    self.position += 2;
                    Token::GreaterEqual
                } else {
                    self.position += 1;
                    Token::Greater
                }
            }
            '<' => {
                if self.input[self.position..].starts_with("<=") {
                    self.position += 2;
                    Token::LessEqual
                } else if self.input[self.position..].starts_with("<>") {
                    self.position += 2;
                    Token::NotEqual
                } else {
                    self.position += 1;
                    Token::Less
                }
            }
            _ if ch.is_alphabetic() || ch == '_' => {
                let ident = self.read_identifier();
                match ident.to_uppercase().as_str() {
                    "ADD" => Token::Add,
                    "MODIFY" => Token::Modify,
                    "COLUMN" => Token::Column,
                    "SELECT" => Token::Select,
                    "FROM" => Token::From,
                    "WHERE" => Token::Where,
                    "INSERT" => Token::Insert,
                    "INTO" => Token::Into,
                    "VALUES" => Token::Values,
                    "UPDATE" => Token::Update,
                    "USING" => Token::Using,
                    "SET" => Token::Set,
                    "DELETE" => Token::Delete,
                    "CREATE" => Token::Create,
                    "TABLE" => Token::Table,
                    "DROP" => Token::Drop,
                    "ALTER" => Token::Alter,
                    "UNIQUE" => Token::Unique,
                    "INDEX" => Token::Index,
                    "ON" => Token::On,
                    "PRIMARY" => Token::Primary,
                    "KEY" => Token::Key,
                    "DUPLICATE" => Token::Duplicate,
                    "REPLACE" => Token::Replace,
                    "IGNORE" => Token::Ignore,
                    "BEGIN" => Token::Begin,
                    "COMMIT" => Token::Commit,
                    "ROLLBACK" => Token::Rollback,
                    "GRANT" => Token::Grant,
                    "REVOKE" => Token::Revoke,
                    "TO" => Token::To,
                    "GROUP" => Token::Group,
                    "BY" => Token::By,
                    "HAVING" => Token::Having,
                    "ORDER" => Token::Order,
                    "ASC" => Token::Asc,
                    "DESC" => Token::Desc,
                    "NULLS" => Token::Nulls,
                    "FIRST" => Token::First,
                    "LAST" => Token::Last,
                    "ROW_NUMBER" => Token::RowNumber,
                    "RANK" => Token::Rank,
                    "DENSE_RANK" => Token::DenseRank,
                    "LEAD" => Token::Lead,
                    "LAG" => Token::Lag,
                    "FIRST_VALUE" => Token::FirstValue,
                    "LAST_VALUE" => Token::LastValue,
                    "NTH_VALUE" => Token::NthValue,
                    "OVER" => Token::Over,
                    "PARTITION" => Token::Partition,
                    "WITHIN" => Token::Within,
                    "ROWS" => Token::Rows,
                    "RANGE" => Token::Range,
                    "GROUPS" => Token::Groups,
                    "UNBOUNDED" => Token::Unbounded,
                    "PRECEDING" => Token::Preceding,
                    "FOLLOWING" => Token::Following,
                    "EXCLUDE" => Token::Exclude,
                    "CURRENT" => Token::Current,
                    "TIES" => Token::Ties,
                    "NO" => Token::NoOthers,
                    "BETWEEN" => Token::Between,
                    "WITH" => Token::With,
                    "RECURSIVE" => Token::Recursive,
                    "MERGE" => Token::Merge,
                    "TRUNCATE" => Token::Truncate,
                    "WHEN" => Token::When,
                    "MATCHED" => Token::Matched,
                    "ALL" => Token::All,
                    "ANALYZE" => Token::Analyze,
                    "EXPLAIN" => Token::Explain,
                    "UNION" => Token::Union,
                    "INTERSECT" => Token::Intersect,
                    "EXCEPT" => Token::Except,
                    "TRIGGER" => Token::Trigger,
                    "DO" => Token::Do,
                    "BEFORE" => Token::Before,
                    "AFTER" => Token::After,
                    "FOR" => Token::For,
                    "EACH" => Token::Each,
                    "ROW" => Token::Row,
                    "NEW" => Token::New,
                    "OLD" => Token::Old,
                    "REFERENCING" => Token::Referencing,
                    "PROCEDURE" => Token::Procedure,
                    "CALL" => Token::Call,
                    "RETURN" => Token::Return,
                    "IF" => Token::If,
                    "THEN" => Token::Then,
                    "ELSE" => Token::Else,
                    "ELSIF" => Token::Elsif,
                    "END IF" => Token::EndIf,
                    "WHILE" => Token::While,
                    "LOOP" => Token::Loop,
                    "END LOOP" => Token::EndLoop,
                    "LEAVE" => Token::Leave,
                    "ITERATE" => Token::Iterate,
                    "SIGNAL" => Token::Signal,
                    "DELIMITER" => Token::Delimiter,
                    "VIEW" => Token::View,
                    "AS" => Token::As,
                    "SHOW" => Token::Show,
                    "STATUS" => Token::Status,
                    "PROCESSLIST" => Token::Processlist,
                    "INTEGER" | "INT" => Token::Integer,
                    "TEXT" | "VARCHAR" | "CHAR" => Token::Text,
                    "FLOAT" | "DOUBLE" | "REAL" => Token::Float,
                    "DECIMAL" | "NUMERIC" => Token::Decimal,
                    "BOOLEAN" | "BOOL" => Token::Boolean,
                    "BLOB" => Token::Blob,
                    "JSON" => Token::Json,
                    "DATE" => Token::Date,
                    "TIMESTAMP" => Token::Timestamp,
                    "LENGTH" => Token::Length,
                    "UPPER" => Token::Upper,
                    "LOWER" => Token::Lower,
                    "SUBSTR" => Token::Substr,
                    "SUBSTRING" => Token::Substring,
                    "TRIM" => Token::Trim,
                    "NOW" => Token::Now,
                    "CURDATE" => Token::Curdate,
                    "CURTIME" => Token::Curtime,
                    "DATE_ADD" => Token::DateAdd,
                    "DATE_FORMAT" => Token::DateFormat,
                    "COUNT" => Token::Count,
                    "SUM" => Token::Sum,
                    "AVG" => Token::Avg,
                    "MIN" => Token::Min,
                    "MAX" => Token::Max,
                    "TRUE" => Token::BooleanLiteral(true),
                    "FALSE" => Token::BooleanLiteral(false),
                    "AND" => Token::And,
                    "OR" => Token::Or,
                    "NOT" => Token::Not,
                    "AUTO_INCREMENT" | "AUTOINCREMENT" => Token::AutoIncrement,
                    "REFERENCES" => Token::References,
                    "COPY" => Token::Copy,
                    "FORMAT" => Token::Format,
                    "PARQUET" => Token::Parquet,
                    "KILL" => Token::Kill,
                    "CONNECTION" => Token::Connection,
                    "QUERY" => Token::Query,
                    _ => Token::Identifier(ident),
                }
            }
            _ if ch.is_ascii_digit() => Token::NumberLiteral(self.read_number()),
            _ => {
                self.position += 1;
                Token::Identifier(ch.to_string())
            }
        }
    }

    /// Tokenize the entire input and return a vector of tokens
    pub fn tokenize(&mut self) -> Vec<Token> {
        let mut tokens = Vec::new();
        loop {
            let token = self.next_token();
            tokens.push(token.clone());
            if matches!(token, Token::Eof) {
                break;
            }
        }
        tokens
    }
}

/// Convenience function to tokenize a SQL string
pub fn tokenize(sql: &str) -> Vec<Token> {
    let mut lexer = Lexer::new(sql);
    lexer.tokenize()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_simple_select() {
        let mut lexer = Lexer::new("SELECT id FROM users WHERE id = 1");
        let tokens = lexer.tokenize();
        assert_eq!(tokens[0], Token::Select);
        assert_eq!(tokens[1], Token::Identifier("id".to_string()));
        assert_eq!(tokens[2], Token::From);
        assert_eq!(tokens[3], Token::Identifier("users".to_string()));
        assert_eq!(tokens[4], Token::Where);
        assert_eq!(tokens[5], Token::Identifier("id".to_string()));
        assert_eq!(tokens[6], Token::Equal);
        assert_eq!(tokens[7], Token::NumberLiteral("1".to_string()));
        assert_eq!(tokens.last().unwrap(), &Token::Eof);
    }

    #[test]
    fn test_operators() {
