#[test]
fn test_parse_insert_ignore() {
    let result = parse("INSERT IGNORE INTO users (id, name) VALUES (1, 'Alice')");
    assert!(result.is_ok(), "Error: {:?}", result.err());
    match result.unwrap() {
        Statement::Insert(i) => {
