//! SQLRustGo Planner Module
//!
//! This module provides query planning and optimization interfaces.

pub mod logical_plan;
pub mod optimizer;
pub mod physical_plan;
#[allow(clippy::module_inception)]
pub mod planner;
pub mod prepared;

// TODO: Add these modules after migration
// pub mod analyzer;
// pub mod cost;
// pub mod executor;

pub use logical_plan::{LogicalPlan, SetOperationType};
pub use optimizer::{DefaultOptimizer, NoOpOptimizer, Optimizer, OptimizerRule};
pub use physical_plan::{
    AggregateExec, AnyAllSubqueryExec, ColumnarScanExec, ExistsExec, FilterExec, HashJoinExec,
    InSubqueryExec, IndexScanExec, LimitExec, PhysicalPlan, ProjectionExec, ScalarSubqueryExec,
    SeqScanExec, SetOperationExec, SortExec, SortMergeJoinExec, WindowExec,
};
pub use planner::{DefaultPlanner, NoOpPlanner, Planner};
pub use prepared::{PreparedStatement, PreparedStatementManager};

use sqlrustgo_types::Value;
use std::fmt;

#[derive(Debug, Clone, PartialEq)]
pub enum JoinType {
    Inner,
    Left,
    Right,
    Full,
    Cross,
    LeftSemi,
    LeftAnti,
    RightSemi,
    RightAnti,
}

#[derive(Debug, Clone, PartialEq)]
pub enum AggregateFunction {
    Count,
    Sum,
    Avg,
    Min,
    Max,
}

#[derive(Debug, Clone, PartialEq)]
pub enum WindowFunction {
    RowNumber,
    Rank,
    DenseRank,
    Lead,
    Lag,
    FirstValue,
    LastValue,
    NthValue,
    // Aggregate window functions
    Sum,
    Avg,
    Count,
    Min,
    Max,
}

/// Window frame type for window functions
#[derive(Debug, Clone, PartialEq)]
pub enum WindowFrame {
    /// ROWS mode - physical row offset
    Rows {
        start: FrameBound,
        end: FrameBound,
        exclude: ExcludeMode,
    },
    /// RANGE mode - logical range based on ORDER BY values
    Range {
        start: FrameBound,
        end: FrameBound,
        exclude: ExcludeMode,
    },
    /// GROUPS mode - peer groups based on ORDER BY
    Groups {
        start: FrameBound,
        end: FrameBound,
        exclude: ExcludeMode,
    },
}

/// Frame bound for window frame start/end
#[derive(Debug, Clone, PartialEq)]
pub enum FrameBound {
    /// UNBOUNDED PRECEDING
    UnboundedPreceding,
    /// PRECEDING(n) - n rows/groups before current
    Preceding(i64),
    /// CURRENT ROW
    CurrentRow,
    /// FOLLOWING(n) - n rows/groups after current
    Following(i64),
    /// UNBOUNDED FOLLOWING
    UnboundedFollowing,
}

/// EXCLUDE mode for window frame
#[derive(Debug, Clone, PartialEq)]
pub enum ExcludeMode {
    /// No exclusion (default)
    None,
    /// EXCLUDE CURRENT ROW
    CurrentRow,
    /// EXCLUDE GROUP
    Group,
    /// EXCLUDE TIES
    Ties,
    /// EXCLUDE NO OTHERS
    NoOthers,
}

#[derive(Debug, Clone, PartialEq)]
pub enum Operator {
    Eq,
    NotEq,
    Lt,
    LtEq,
    Gt,
    GtEq,
    Plus,
    Minus,
    Multiply,
    Divide,
    Modulo,
    And,
    Or,
    Not,
    Like,
    Concatenate,
}

#[derive(Debug, Clone, PartialEq)]
pub struct SortExpr {
    pub expr: Expr,
    pub asc: bool,
    pub nulls_first: bool,
}

#[derive(Debug, Clone, PartialEq)]
pub struct Column {
    pub relation: Option<String>,
    pub name: String,
}

impl Column {
    pub fn new(name: String) -> Self {
        Self {
            relation: None,
            name,
        }
    }

    pub fn new_qualified(relation: String, name: String) -> Self {
        Self {
            relation: Some(relation),
            name,
        }
    }
}

impl fmt::Display for Column {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match &self.relation {
            Some(rel) => write!(f, "{}.{}", rel, self.name),
            None => write!(f, "{}", self.name),
        }
    }
}

/// Subquery type for classification
#[derive(Debug, Clone, PartialEq)]
pub enum SubqueryType {
    /// Scalar subquery - returns single value
    Scalar,
    /// IN subquery - checks if value is in subquery results
    In,
    /// EXISTS subquery - checks if subquery returns any rows
    Exists,
    /// ANY subquery - compares with any result (synonym for SOME)
    Any,
    /// ALL subquery - compares with all results
    All,
}

/// Subquery expression with its type and associated expression
#[derive(Debug, Clone, PartialEq)]
pub struct Subquery {
    pub subquery_type: SubqueryType,
    pub expr: Box<Expr>,
    pub plan: Box<LogicalPlan>,
}

#[derive(Debug, Clone, PartialEq)]
pub enum Expr {
    Column(Column),
    Literal(Value),
    BinaryExpr {
        left: Box<Expr>,
        op: Operator,
        right: Box<Expr>,
    },
    UnaryExpr {
        op: Operator,
        expr: Box<Expr>,
    },
    AggregateFunction {
        func: AggregateFunction,
        args: Vec<Expr>,
        distinct: bool,
    },
    WindowFunction {
        func: WindowFunction,
        args: Vec<Expr>,
        partition_by: Vec<Expr>,
        order_by: Vec<SortExpr>,
        frame: Option<WindowFrame>,
    },
    Alias {
        expr: Box<Expr>,
        name: String,
    },
    Wildcard,
    QualifiedWildcard {
        qualifier: String,
    },
    /// Scalar subquery returning single value
    ScalarSubquery(Box<LogicalPlan>),
    /// IN subquery: expr IN (SELECT ...)
    InSubquery {
        expr: Box<Expr>,
        subquery: Box<LogicalPlan>,
    },
    /// EXISTS subquery: EXISTS (SELECT ...)
    Exists(Box<LogicalPlan>),
    /// ANY/ALL subquery: expr OP ANY/ALL (SELECT ...)
    AnyAll {
        expr: Box<Expr>,
        op: Operator,
        subquery: Box<LogicalPlan>,
        any_all: SubqueryType,
    },
    /// Parameter placeholder for prepared statements (e.g., ? or $1)
    Parameter {
        index: usize,
    },
}

impl Expr {
    pub fn column(name: &str) -> Self {
        Expr::Column(Column::new(name.to_string()))
    }

    pub fn literal(value: Value) -> Self {
        Expr::Literal(value)
    }

    pub fn binary_expr(left: Expr, op: Operator, right: Expr) -> Self {
        Expr::BinaryExpr {
            left: Box::new(left),
            op,
            right: Box::new(right),
        }
    }

    pub fn evaluate(&self, row: &[Value], schema: &Schema) -> Option<Value> {
        match self {
            Expr::Column(col) => {
                let idx = schema.field_index(&col.name)?;
                row.get(idx).cloned()
            }
            Expr::Literal(val) => Some(val.clone()),
            Expr::BinaryExpr { left, op, right } => {
                let lv = left.evaluate(row, schema)?;
                let rv = right.evaluate(row, schema)?;
                evaluate_binary_op(&lv, op, &rv)
            }
            Expr::UnaryExpr { op, expr } => {
                let v = expr.evaluate(row, schema)?;
                evaluate_unary_op(&v, op)
            }
            Expr::AggregateFunction { .. } => None,
            Expr::WindowFunction { .. } => None,
            Expr::Alias { expr, .. } => expr.evaluate(row, schema),
            Expr::Wildcard => None,
            Expr::QualifiedWildcard { .. } => None,
            // Subquery expressions cannot be evaluated row-by-row
            Expr::ScalarSubquery(_) => None,
            Expr::InSubquery { .. } => None,
            Expr::Exists(_) => None,
            Expr::AnyAll { .. } => None,
            // Parameter placeholder - cannot be evaluated without bound values
            Expr::Parameter { .. } => None,
        }
    }

    pub fn matches(&self, row: &[Value], schema: &Schema) -> bool {
        if let Some(value) = self.evaluate(row, schema) {
            value.to_bool()
        } else {
            false
        }
    }
}

fn evaluate_binary_op(left: &Value, op: &Operator, right: &Value) -> Option<Value> {
    use sqlrustgo_types::Value::*;
    use Operator::*;

    match (left, op, right) {
        (Integer(l), Eq, Integer(r)) => Some(Boolean(l == r)),
        (Integer(l), NotEq, Integer(r)) => Some(Boolean(l != r)),
        (Integer(l), Lt, Integer(r)) => Some(Boolean(l < r)),
        (Integer(l), LtEq, Integer(r)) => Some(Boolean(l <= r)),
        (Integer(l), Gt, Integer(r)) => Some(Boolean(l > r)),
        (Integer(l), GtEq, Integer(r)) => Some(Boolean(l >= r)),
        (Text(l), Eq, Text(r)) => Some(Boolean(l == r)),
        (Text(l), NotEq, Text(r)) => Some(Boolean(l != r)),
        (Text(l), Lt, Text(r)) => Some(Boolean(l < r)),
        (Text(l), LtEq, Text(r)) => Some(Boolean(l <= r)),
        (Text(l), Gt, Text(r)) => Some(Boolean(l > r)),
        (Text(l), GtEq, Text(r)) => Some(Boolean(l >= r)),
        (Integer(l), Plus, Integer(r)) => Some(Integer(l + r)),
        (Integer(l), Minus, Integer(r)) => Some(Integer(l - r)),
        (Integer(l), Multiply, Integer(r)) => Some(Integer(l * r)),
        (Integer(l), Divide, Integer(r)) => {
            if *r != 0 {
                Some(Integer(l / r))
            } else {
                None
            }
        }
        _ => None,
    }
}

fn evaluate_unary_op(value: &Value, op: &Operator) -> Option<Value> {
    use sqlrustgo_types::Value::*;

    match (value, op) {
        (Integer(v), Operator::Not) => Some(Boolean(*v == 0)),
        (Boolean(v), Operator::Not) => Some(Boolean(!v)),
        (Integer(v), Operator::Minus) => Some(Integer(-v)),
        _ => None,
    }
}

impl fmt::Display for Expr {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Expr::Column(col) => write!(f, "{}", col),
            Expr::Literal(val) => write!(f, "{}", val),
            Expr::BinaryExpr { left, op, right } => {
                write!(f, "({} {} {})", left, op, right)
            }
            Expr::UnaryExpr { op, expr } => write!(f, "({} {})", op, expr),
            Expr::AggregateFunction {
                func,
                args,
                distinct,
            } => {
                let func_name = match func {
                    AggregateFunction::Count => "COUNT",
                    AggregateFunction::Sum => "SUM",
                    AggregateFunction::Avg => "AVG",
                    AggregateFunction::Min => "MIN",
                    AggregateFunction::Max => "MAX",
                };
                let distinct_str = if *distinct { "DISTINCT " } else { "" };
                let args_str: Vec<String> = args.iter().map(|a| a.to_string()).collect();
                write!(f, "{}({}{})", func_name, distinct_str, args_str.join(", "))
            }
            Expr::WindowFunction {
                func,
                args,
                partition_by,
                order_by,
                frame,
            } => {
                let func_name = match func {
                    WindowFunction::RowNumber => "ROW_NUMBER",
                    WindowFunction::Rank => "RANK",
                    WindowFunction::DenseRank => "DENSE_RANK",
                    WindowFunction::Lead => "LEAD",
                    WindowFunction::Lag => "LAG",
                    WindowFunction::FirstValue => "FIRST_VALUE",
                    WindowFunction::LastValue => "LAST_VALUE",
                    WindowFunction::NthValue => "NTH_VALUE",
                    WindowFunction::Sum => "SUM",
                    WindowFunction::Avg => "AVG",
                    WindowFunction::Count => "COUNT",
                    WindowFunction::Min => "MIN",
                    WindowFunction::Max => "MAX",
                };
                let args_str: Vec<String> = args.iter().map(|a| a.to_string()).collect();
                write!(f, "{}({})", func_name, args_str.join(", "))?;

                // Add PARTITION BY clause
                if !partition_by.is_empty() {
                    let partition_str: Vec<String> =
                        partition_by.iter().map(|p| p.to_string()).collect();
                    write!(f, " PARTITION BY {}", partition_str.join(", "))?;
                }

                // Add ORDER BY clause
                if !order_by.is_empty() {
                    let order_str: Vec<String> = order_by.iter().map(|o| o.to_string()).collect();
                    write!(f, " ORDER BY {}", order_str.join(", "))?;
                }

                // Add window frame specification
                if let Some(fr) = frame {
                    write!(f, " {}", fr)?;
                }

                Ok(())
            }
            Expr::Alias { expr, name } => write!(f, "{} AS {}", expr, name),
            Expr::Wildcard => write!(f, "*"),
            Expr::QualifiedWildcard { qualifier } => write!(f, "{}.*", qualifier),
            Expr::ScalarSubquery(_) => write!(f, "(SELECT ...)"),
            Expr::InSubquery { expr, .. } => write!(f, "{} IN (SELECT ...)", expr),
            Expr::Exists(_) => write!(f, "EXISTS (SELECT ...)"),
            Expr::AnyAll {
                expr, op, any_all, ..
            } => {
                let any_all_str = match any_all {
                    SubqueryType::Any => "ANY",
                    SubqueryType::All => "ALL",
                    _ => "UNKNOWN",
                };
                write!(f, "{} {} {} (SELECT ...)", expr, op, any_all_str)
            }
            Expr::Parameter { index } => write!(f, "?{}", index),
        }
    }
}

impl fmt::Display for Operator {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Operator::Eq => write!(f, "="),
            Operator::NotEq => write!(f, "!="),
            Operator::Lt => write!(f, "<"),
            Operator::LtEq => write!(f, "<="),
            Operator::Gt => write!(f, ">"),
            Operator::GtEq => write!(f, ">="),
            Operator::Plus => write!(f, "+"),
            Operator::Minus => write!(f, "-"),
            Operator::Multiply => write!(f, "*"),
            Operator::Divide => write!(f, "/"),
            Operator::Modulo => write!(f, "%"),
            Operator::And => write!(f, "AND"),
            Operator::Or => write!(f, "OR"),
            Operator::Not => write!(f, "NOT"),
            Operator::Like => write!(f, "LIKE"),
            Operator::Concatenate => write!(f, "||"),
        }
    }
}

impl fmt::Display for SortExpr {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{} {}", self.expr, if self.asc { "ASC" } else { "DESC" })
    }
}

impl fmt::Display for WindowFrame {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            WindowFrame::Rows {
                start,
                end,
                exclude,
            } => {
                write!(f, "ROWS {} {}", start, end)?;
                if *exclude != ExcludeMode::None {
                    write!(f, " {}", exclude)?;
                }
                Ok(())
            }
            WindowFrame::Range {
                start,
                end,
                exclude,
            } => {
                write!(f, "RANGE {} {}", start, end)?;
                if *exclude != ExcludeMode::None {
                    write!(f, " {}", exclude)?;
                }
                Ok(())
            }
            WindowFrame::Groups {
                start,
                end,
                exclude,
            } => {
                write!(f, "GROUPS {} {}", start, end)?;
                if *exclude != ExcludeMode::None {
                    write!(f, " {}", exclude)?;
                }
                Ok(())
            }
        }
    }
}

impl fmt::Display for FrameBound {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            FrameBound::UnboundedPreceding => write!(f, "UNBOUNDED PRECEDING"),
            FrameBound::Preceding(n) => write!(f, "PRECEDING({})", n),
            FrameBound::CurrentRow => write!(f, "CURRENT ROW"),
            FrameBound::Following(n) => write!(f, "FOLLOWING({})", n),
            FrameBound::UnboundedFollowing => write!(f, "UNBOUNDED FOLLOWING"),
        }
    }
}

impl fmt::Display for ExcludeMode {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            ExcludeMode::None => write!(f, "EXCLUDE NO OTHERS"),
            ExcludeMode::CurrentRow => write!(f, "EXCLUDE CURRENT ROW"),
            ExcludeMode::Group => write!(f, "EXCLUDE GROUP"),
            ExcludeMode::Ties => write!(f, "EXCLUDE TIES"),
            ExcludeMode::NoOthers => write!(f, "EXCLUDE NO OTHERS"),
        }
    }
}

#[derive(Debug, Clone, PartialEq, Default)]
pub struct Schema {
    pub fields: Vec<Field>,
}

impl Schema {
    pub fn new(fields: Vec<Field>) -> Self {
        Self { fields }
    }

    pub fn empty() -> Self {
        Self { fields: vec![] }
    }

    pub fn field(&self, name: &str) -> Option<&Field> {
        self.fields.iter().find(|f| f.name == name)
    }

    pub fn field_index(&self, name: &str) -> Option<usize> {
        self.fields.iter().position(|f| f.name == name)
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct Field {
    pub name: String,
    pub data_type: DataType,
    pub nullable: bool,
}

impl Field {
    pub fn new(name: String, data_type: DataType) -> Self {
        Self {
            name,
            data_type,
            nullable: true,
        }
    }

    pub fn new_not_null(name: String, data_type: DataType) -> Self {
        Self {
            name,
            data_type,
            nullable: false,
        }
    }
}

#[derive(Debug, Clone, PartialEq)]
pub enum DataType {
    Boolean,
    Integer,
    Float,
    Decimal,
    Text,
    Json,
    Blob,
    Null,
}

impl DataType {
    pub fn from_sql_type(type_name: &str) -> Self {
        match type_name.to_uppercase().as_str() {
            "INTEGER" | "INT" => DataType::Integer,
            "FLOAT" | "DOUBLE" | "REAL" => DataType::Float,
            "DECIMAL" | "NUMERIC" => DataType::Decimal,
            "TEXT" | "VARCHAR" | "CHAR" => DataType::Text,
            "JSON" => DataType::Json,
            "BLOB" | "BINARY" => DataType::Blob,
            "BOOLEAN" | "BOOL" => DataType::Boolean,
            _ => DataType::Null,
        }
    }

    pub fn estimate_size(&self) -> usize {
        match self {
            DataType::Boolean => 1,
            DataType::Integer => 8,
            DataType::Float => 8,
            DataType::Decimal => 16,
            DataType::Text => 64,
            DataType::Json => 128,
            DataType::Blob => 256,
            DataType::Null => 0,
        }
    }
}

impl fmt::Display for DataType {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            DataType::Boolean => write!(f, "BOOLEAN"),
            DataType::Integer => write!(f, "INTEGER"),
            DataType::Float => write!(f, "FLOAT"),
            DataType::Decimal => write!(f, "DECIMAL"),
            DataType::Text => write!(f, "TEXT"),
            DataType::Json => write!(f, "JSON"),
            DataType::Blob => write!(f, "BLOB"),
            DataType::Null => write!(f, "NULL"),
        }
    }
}

