fn extract_join_keys(condition: Option<&Expr>, left_side: bool) -> Vec<Expr> {
    match condition {
        Some(Expr::BinaryExpr { left, right, .. }) => {
            if left_side {
                vec![(**left).clone()]
            } else {
                vec![(**right).clone()]
            }
        }
        _ => vec![],
    }
}

