//! SQLRustGo TCP Server
//!
//! A simple TCP server that accepts SQL queries and returns results.

use sqlrustgo::{parse, ExecutionEngine, SqlError};
use sqlrustgo_server::SecurityIntegration;
use sqlrustgo_storage::MemoryStorage;
use std::io::{Read, Write};
use std::net::{SocketAddr, TcpListener, TcpStream};
use std::sync::{Arc, RwLock};

/// Handle a single client connection
fn handle_client(
    mut stream: TcpStream,
    engine: Arc<RwLock<ExecutionEngine>>,
    security: Arc<SecurityIntegration>,
) -> std::io::Result<()> {
    let peer_addr = stream
        .peer_addr()
        .unwrap_or(SocketAddr::from(([0, 0, 0, 0], 0)));
    let ip = peer_addr.ip().to_string();
    let user = "anonymous".to_string();

    let session_id = security.create_secure_session(user.clone(), ip.clone());

    let mut buffer = [0u8; 4096];

    loop {
        let bytes_read = match stream.read(&mut buffer) {
            Ok(0) => {
                security.close_secure_session(session_id, user);
                return Ok(());
            }
            Ok(n) => n,
            Err(e) => {
                security.log_error(&user, &format!("Read error: {}", e), session_id);
                security.close_secure_session(session_id, user);
                return Err(e);
            }
        };

        let received = String::from_utf8_lossy(&buffer[..bytes_read]);
        let queries: Vec<&str> = received.lines().collect();

        for query in queries {
            let query = query.trim();
            if query.is_empty() {
                continue;
            }

            let start = std::time::Instant::now();

            let result = {
                let mut eng = engine.write().unwrap();
                match parse(query) {
                    Ok(statement) => eng.execute(statement),
                    Err(e) => Err(SqlError::ParseError(format!("{:?}", e))),
                }
            };

            let duration_ms = start.elapsed().as_millis() as u64;
            let rows = result.as_ref().map(|r| r.affected_rows as u64).unwrap_or(0);

            if parse(query).is_ok() && is_ddl(query) {
                security.log_ddl(&user, query, session_id);
            }

            security.log_sql_execution(&user, query, duration_ms, rows, session_id);

            let response = match result {
                Ok(result) => serde_json::json!({
                    "status": "ok",
                    "rows_affected": result.affected_rows,
                    "result": result.rows
                })
                .to_string(),
                Err(e) => {
                    security.log_error(&user, &e.to_string(), session_id);
                    serde_json::json!({
                        "status": "error",
                        "error": e.to_string()
                    })
                    .to_string()
                }
            };

            if let Err(e) = stream.write_all(response.as_bytes()) {
                security.log_error(&user, &format!("Write error: {}", e), session_id);
                return Err(e);
            }
            if let Err(e) = stream.write_all(b"\n") {
                return Err(e);
            }
            if let Err(e) = stream.flush() {
                return Err(e);
            }
        }
    }
}

fn is_ddl(query: &str) -> bool {
    let upper = query.to_uppercase();
    upper.starts_with("CREATE")
        || upper.starts_with("DROP")
        || upper.starts_with("ALTER")
        || upper.starts_with("TRUNCATE")
}

fn main() {
    env_logger::Builder::from_env(env_logger::Env::default().default_filter_or("info")).init();

    let addr = "127.0.0.1:4000";
    println!("SQLRustGo TCP Server v1.6.1");
    println!("Listening on {}", addr);

    let storage = Arc::new(RwLock::new(MemoryStorage::new()));
    let engine = Arc::new(RwLock::new(ExecutionEngine::new(storage)));
    let security = Arc::new(SecurityIntegration::new());

    println!("Security: audit logging enabled");

    let listener = TcpListener::bind(addr).expect("Failed to bind to address");
    println!("Ready to accept connections");

    let security_for_shutdown = security.clone();
    ctrlc::set_handler(move || {
        println!("\nShutting down...");
        let stats = security_for_shutdown.get_security_stats();
        println!(
            "Security stats: {} events, {} sessions",
            stats.audit_total_events, stats.total_sessions
        );
        std::process::exit(0);
    })
    .expect("Error setting Ctrl-C handler");

    for stream in listener.incoming() {
        match stream {
            Ok(stream) => {
                let engine = engine.clone();
                let security = security.clone();
                std::thread::spawn(move || {
                    if let Err(e) = handle_client(stream, engine, security) {
                        eprintln!("Client handler error: {}", e);
                    }
                });
            }
            Err(e) => {
                eprintln!("Connection error: {}", e);
            }
        }
    }
}

//! Metrics Endpoint Module
//!
//! Provides /metrics endpoint for Prometheus-compatible metrics exposition.

use actix_web::{web, HttpResponse, Responder};
use sqlrustgo_common::metrics::{MetricValue, Metrics};
use std::collections::HashMap;
use std::sync::{Arc, RwLock};

#[derive(Clone)]
pub struct MetricsRegistry {
    metrics_collectors: Vec<Arc<RwLock<dyn Metrics>>>,
    custom_metrics: HashMap<String, String>,
    help_texts: HashMap<String, String>,
}

impl MetricsRegistry {
    pub fn new() -> Self {
        Self {
            metrics_collectors: Vec::new(),
            custom_metrics: HashMap::new(),
            help_texts: HashMap::new(),
        }
    }

    pub fn register_metrics(&mut self, metrics: Arc<RwLock<dyn Metrics>>) {
        self.metrics_collectors.push(metrics);
    }

    pub fn register_custom_metric(&mut self, name: String, value: String) {
        self.custom_metrics.insert(name, value);
    }

    pub fn register_help(&mut self, name: String, help: String) {
        self.help_texts.insert(name, help);
    }

    pub fn to_prometheus_format(&self) -> String {
        let mut output = String::with_capacity(4096);

        for collector in &self.metrics_collectors {
            if let Ok(metrics) = collector.read() {
                let metric_names = metrics.get_metric_names();
                for name in metric_names {
                    if let Some(value) = metrics.get_metric(&name) {
                        if let Some(help) = self.help_texts.get(&name) {
                            use std::fmt::Write;
                            let _ = writeln!(output, "# HELP sqlrustgo_{} {}", name, help);
                        }

                        let metric_type = match &value {
                            MetricValue::Counter(_) => "counter",
                            MetricValue::Gauge(_) => "gauge",
                            MetricValue::Histogram(_) => "histogram",
                            MetricValue::Timing(_) => "gauge",
                        };

                        use std::fmt::Write;
                        let _ = writeln!(output, "# TYPE sqlrustgo_{} {}", name, metric_type);

                        let metric_value = match &value {
                            MetricValue::Counter(v) => v.to_string(),
                            MetricValue::Gauge(v) => v.to_string(),
                            MetricValue::Histogram(buckets) => {
                                let mut result = String::new();
                                for (i, count) in buckets.iter().enumerate() {
                                    use std::fmt::Write;
                                    let _ = writeln!(
                                        result,
                                        "sqlrustgo_{}{{bucket=\"{}\"}} {}",
                                        name, i, count
                                    );
                                }
                                result
                            }
                            MetricValue::Timing(v) => v.to_string(),
                        };

                        let _ = writeln!(output, "sqlrustgo_{} {}", name, metric_value);
                    }
                }
            }
        }

        for (name, value) in &self.custom_metrics {
            use std::fmt::Write;
            let _ = writeln!(output, "{} {}", name, value);
        }

        output
    }
}

pub async fn metrics_handler(data: web::Data<Arc<RwLock<MetricsRegistry>>>) -> impl Responder {
    let registry = data.read().unwrap();
    let output = registry.to_prometheus_format();

    HttpResponse::Ok()
        .content_type("text/plain; version=0.0.4; charset=utf-8")
        .body(output)
}

pub fn configure_metrics_scope(cfg: &mut web::ServiceConfig) {
    cfg.service(web::resource("/metrics").route(web::get().to(metrics_handler)));
}

impl Default for MetricsRegistry {
    fn default() -> Self {
        Self::new()
    }
}

