    #[test]
    fn test_buffer_pool_pin_unpin() {
        let pool = BufferPool::new(10);
        pool.insert(Arc::new(Page::new(1)));

        assert!(!pool.is_pinned(1));
        assert_eq!(pool.pin_count(1), 0);

        pool.pin(1);
        assert!(pool.is_pinned(1));
        assert_eq!(pool.pin_count(1), 1);

        pool.pin(1);
        assert_eq!(pool.pin_count(1), 2);

        assert!(!pool.unpin(1)); // Still pinned
        assert_eq!(pool.pin_count(1), 1);

        assert!(pool.unpin(1)); // Now unpinned
        assert!(!pool.is_pinned(1));
        assert_eq!(pool.pin_count(1), 0);
    }

    #[test]
    fn test_buffer_pool_skip_pinned_on_eviction() {
        let pool = BufferPool::new(3); // Capacity of 3

        // Insert 3 pages
        pool.insert(Arc::new(Page::new(1)));
        pool.insert(Arc::new(Page::new(2)));
        pool.insert(Arc::new(Page::new(3)));

        // Access pages to set LRU order: 3 is MRU, 1 is LRU
        let _ = pool.get(1);
        let _ = pool.get(2);
        let _ = pool.get(3);
        // LRU order is now: [3, 2, 1] (3 is front/MRU, 1 is back/LRU)

        // Pin the LRU page (page 1)
        pool.pin(1);

        // Insert new page - should evict page 2 (LRU), NOT page 1 (which is pinned)
        pool.insert(Arc::new(Page::new(4)));

        // Page 1 should still be there (pinned), page 2 should be evicted
        assert!(pool.get(1).is_some()); // Pinned page should remain
        assert!(pool.get(2).is_none()); // Should be evicted
        assert!(pool.get(3).is_some());
        assert!(pool.get(4).is_some());

        // Unpin page 1
        pool.unpin(1);

        // Insert another page - now page 1 is the only unpinned LRU candidate
        pool.insert(Arc::new(Page::new(5)));

        // Now page 1 should be evicted
        assert!(pool.get(1).is_none()); // Now evicted
    }

    #[test]
    fn test_buffer_pool_unpin_allows_eviction() {
        let pool = BufferPool::new(2);

        pool.insert(Arc::new(Page::new(1)));
        pool.insert(Arc::new(Page::new(2)));

        // Pin both pages
        pool.pin(1);
        pool.pin(2);

        // Try to insert new page - cannot evict any (both pinned)
        pool.insert(Arc::new(Page::new(3)));

        // Pool is still at capacity (pinned pages can't be evicted)
        assert_eq!(pool.len(), 2);

        // Unpin one page
        pool.unpin(1);

        // Now insert should evict page 1
        pool.insert(Arc::new(Page::new(4)));

        assert!(pool.get(1).is_none()); // Evicted
        assert!(pool.get(2).is_some()); // Still pinned
        assert!(pool.get(3).is_some());
        assert!(pool.get(4).is_some());
    }
}

//! Buffer Pool Metrics Implementation
//!
//! Implements the Metrics trait for BufferPool to track performance metrics.

use crate::buffer_pool::{BufferPool, BufferPoolStats};
use sqlrustgo_common::metrics::Metrics;
use std::sync::Arc;

pub struct BufferPoolMetrics {
    buffer_pool: Arc<BufferPool>,
    queries_total: std::sync::atomic::AtomicU64,
    queries_failed: std::sync::atomic::AtomicU64,
    query_duration_ns: std::sync::atomic::AtomicU64,
    rows_processed: std::sync::atomic::AtomicU64,
}

impl BufferPoolMetrics {
    pub fn new(buffer_pool: Arc<BufferPool>) -> Self {
        Self {
            buffer_pool,
            queries_total: std::sync::atomic::AtomicU64::new(0),
            queries_failed: std::sync::atomic::AtomicU64::new(0),
            query_duration_ns: std::sync::atomic::AtomicU64::new(0),
            rows_processed: std::sync::atomic::AtomicU64::new(0),
        }
    }

    pub fn buffer_pool_stats(&self) -> BufferPoolStats {
        self.buffer_pool.stats()
    }

    pub fn queries_total(&self) -> u64 {
        self.queries_total
            .load(std::sync::atomic::Ordering::Relaxed)
    }

    pub fn queries_failed(&self) -> u64 {
        self.queries_failed
            .load(std::sync::atomic::Ordering::Relaxed)
    }

    pub fn rows_processed(&self) -> u64 {
        self.rows_processed
            .load(std::sync::atomic::Ordering::Relaxed)
    }
}

impl Metrics for BufferPoolMetrics {
    fn record_query(&mut self, _query_type: &str, duration_ms: u64) {
        self.queries_total
            .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
        let duration_ns = duration_ms * 1_000_000;
        self.query_duration_ns
            .fetch_add(duration_ns, std::sync::atomic::Ordering::Relaxed);
    }

    fn record_error(&mut self) {
        self.queries_failed
            .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
    }

    fn record_error_with_type(&mut self, _error_type: &str) {
        self.queries_failed
            .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
    }

    fn record_bytes_read(&mut self, _bytes: u64) {}

    fn record_bytes_written(&mut self, _bytes: u64) {}

    fn record_cache_hit(&mut self) {}

    fn record_cache_miss(&mut self) {}

    fn get_metric(&self, name: &str) -> Option<sqlrustgo_common::metrics::MetricValue> {
        match name {
            "queries_total" => Some(sqlrustgo_common::metrics::MetricValue::Counter(
                self.queries_total(),
            )),
            "queries_failed" => Some(sqlrustgo_common::metrics::MetricValue::Counter(
                self.queries_failed(),
            )),
            "rows_processed" => Some(sqlrustgo_common::metrics::MetricValue::Counter(
                self.rows_processed(),
            )),
            _ => None,
        }
    }

    fn get_metric_names(&self) -> Vec<String> {
        vec![
            "queries_total".to_string(),
            "queries_failed".to_string(),
            "rows_processed".to_string(),
            "buffer_pool_hits".to_string(),
            "buffer_pool_misses".to_string(),
            "buffer_pool_evictions".to_string(),
        ]
    }

    fn reset(&mut self) {
        self.queries_total
            .store(0, std::sync::atomic::Ordering::Relaxed);
        self.queries_failed
            .store(0, std::sync::atomic::Ordering::Relaxed);
        self.query_duration_ns
            .store(0, std::sync::atomic::Ordering::Relaxed);
        self.rows_processed
            .store(0, std::sync::atomic::Ordering::Relaxed);
    }
}

impl BufferPoolMetrics {
    pub fn record_rows(&self, count: usize) {
        self.rows_processed
            .fetch_add(count as u64, std::sync::atomic::Ordering::Relaxed);
    }
}

