//! PageGuard - RAII wrapper for thread-safe page access
//!
//! PageGuard provides automatic lifecycle management for pages fetched from
//! the buffer pool. When a page is fetched, it's automatically pinned to
//! prevent eviction. When the guard is dropped, the page is automatically
//! unpinned, allowing it to be evicted if needed.
//!
//! ## Usage
//!
//! ```ignore
//! // Page is automatically pinned on fetch
//! let page_guard = buffer_pool.fetch_page(page_id)?;
//!
//! // Use the page...
//! let page = page_guard.page();
//!
//! // Page is automatically unpinned when guard goes out of scope
//! drop(page_guard);
//! // Or implicitly dropped at end of scope
//! ```
//!
//! ## Benefits
//!
//! - **Memory safety**: Never forget to unpin a page
//! - **Exception safety**: Page is unpinned even if code panics
//! - **Clear semantics**: Explicit ownership of pinned page

use std::sync::Arc;

use crate::page::Page;

/// Trait for pool-like types that support pin/unpin
pub trait PoolLike {
    fn pin(&self, page_id: u32);
    fn unpin(&self, page_id: u32) -> bool;
}

/// RAII guard for page access with automatic pin/unpin lifecycle management
///
/// PageGuard wraps a page fetched from the buffer pool and automatically
/// manages its pin count. When created, the page is pinned. When dropped,
/// the page is unpinned, allowing it to be evicted from the buffer pool
/// if necessary.
///
/// # Example
///
/// ```ignore
/// {
///     let guard = pool.fetch_page(42)?;
///     // Page 42 is now pinned and cannot be evicted
///     let page = guard.page();
///     // ... use page ...
/// } // guard dropped, page 42 is now unpinned
/// ```
pub struct PageGuard<'a, P: PoolLike> {
    /// The page being guarded (Arc allows sharing)
    page: Arc<Page>,
    /// Reference to buffer pool for unpin on drop
    pool: &'a P,
    /// Whether this guard owns the pin (false for read-only guards)
    exclusive: bool,
}

impl<'a, P: PoolLike> PageGuard<'a, P> {
    /// Create a new page guard (typically called by BufferPool::fetch_page)
    pub(crate) fn new(page: Arc<Page>, pool: &'a P, exclusive: bool) -> Self {
        // Pin the page when guard is created
        pool.pin(page.page_id());

        Self {
            page,
            pool,
            exclusive,
        }
    }

    /// Get a reference to the underlying page
    #[inline]
    pub fn page(&self) -> &Arc<Page> {
        &self.page
    }

    /// Get the page ID
    #[inline]
    pub fn page_id(&self) -> u32 {
        self.page.page_id()
    }

    /// Get the page data directly
    #[inline]
    pub fn data(&self) -> &[u8] {
        &self.page.data
    }

    /// Check if this is an exclusive (write) guard
    #[inline]
    pub fn is_exclusive(&self) -> bool {
        self.exclusive
    }

    /// Take ownership of the underlying page, bypassing the guard's Drop
    ///
    /// This consumes the guard and returns the page without unpinning it.
    /// The caller takes over responsibility for the page's pin lifecycle.
    ///
    /// Note: The caller MUST ensure the page is eventually unpinned,
    /// otherwise the page will remain pinned indefinitely.
    #[inline]
    pub fn into_page(self) -> Arc<Page> {
        use std::mem::ManuallyDrop;
        // Prevent the guard's Drop from running
        let guard = ManuallyDrop::new(self);
        // Clone the page Arc - this transfers ownership without unpinning
        // ManuallyDrop ensures Drop won't run on the guard
        Arc::clone(&guard.page)
    }
}

impl<'a, P: PoolLike> Drop for PageGuard<'a, P> {
    fn drop(&mut self) {
        // Unpin the page when guard is dropped
        self.pool.unpin(self.page.page_id());
    }
}

impl<'a, P: PoolLike> std::fmt::Debug for PageGuard<'a, P> {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("PageGuard")
            .field("page_id", &self.page.page_id())
            .field("exclusive", &self.exclusive)
            .finish()
    }
}

impl<'a, P: PoolLike> std::ops::Deref for PageGuard<'a, P> {
    type Target = Page;

    fn deref(&self) -> &Self::Target {
        &self.page
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::page::PageType;

    // Mock BufferPool for testing
    struct MockBufferPool {
        pin_count: std::sync::Mutex<std::collections::HashMap<u32, u32>>,
    }

    impl PoolLike for MockBufferPool {
        fn pin(&self, page_id: u32) {
            let mut count = self.pin_count.lock().unwrap();
            *count.entry(page_id).or_insert(0) += 1;
        }

        fn unpin(&self, page_id: u32) -> bool {
            let mut count = self.pin_count.lock().unwrap();
            if let Some(c) = count.get_mut(&page_id) {
                if *c > 0 {
                    *c -= 1;
                    if *c == 0 {
                        count.remove(&page_id);
                    }
                    return true;
                }
            }
            false
        }
    }

    impl MockBufferPool {
        fn new() -> Self {
            Self {
                pin_count: std::sync::Mutex::new(std::collections::HashMap::new()),
            }
        }

        fn pin_count(&self, page_id: u32) -> u32 {
            let count = self.pin_count.lock().unwrap();
            *count.get(&page_id).unwrap_or(&0)
        }
    }

    #[test]
    fn test_page_guard_creation_pins_page() {
        let pool = MockBufferPool::new();
        let page = Arc::new(Page::new(1));

        assert_eq!(pool.pin_count(1), 0);

        let _guard = PageGuard::new(Arc::clone(&page), &pool, true);

        assert_eq!(pool.pin_count(1), 1);
    }

    #[test]
    fn test_page_guard_drop_unpins_page() {
        let pool = MockBufferPool::new();
        let page = Arc::new(Page::new(1));

        {
            let guard = PageGuard::new(Arc::clone(&page), &pool, true);
            assert_eq!(pool.pin_count(1), 1);
        } // guard dropped

        assert_eq!(pool.pin_count(1), 0);
    }

    #[test]
    fn test_page_guard_multiple_pins() {
        let pool = MockBufferPool::new();
        let page = Arc::new(Page::new(1));

        let _guard1 = PageGuard::new(Arc::clone(&page), &pool, true);
        assert_eq!(pool.pin_count(1), 1);

        let _guard2 = PageGuard::new(Arc::clone(&page), &pool, true);
        assert_eq!(pool.pin_count(1), 2);

        // Drop first guard
        drop(_guard1);
        assert_eq!(pool.pin_count(1), 1);

        // Drop second guard
        drop(_guard2);
        assert_eq!(pool.pin_count(1), 0);
    }

    #[test]
    fn test_page_guard_page_access() {
        let pool = MockBufferPool::new();
        let page = Arc::new(Page::new(42));

        let guard = PageGuard::new(Arc::clone(&page), &pool, true);

        assert_eq!(guard.page_id(), 42);
        assert_eq!(guard.page().page_id(), 42);
    }

    #[test]
    fn test_page_guard_debug() {
        let pool = MockBufferPool::new();
        let page = Arc::new(Page::new(1));

        let guard = PageGuard::new(Arc::clone(&page), &pool, true);
        let debug = format!("{:?}", guard);

        assert!(debug.contains("PageGuard"));
        assert!(debug.contains("1"));
    }

    #[test]
    fn test_page_guard_exclusive_flag() {
        let pool = MockBufferPool::new();
        let page = Arc::new(Page::new(1));

        let exclusive_guard = PageGuard::new(Arc::clone(&page), &pool, true);
        assert!(exclusive_guard.is_exclusive());

        let shared_guard = PageGuard::new(Arc::clone(&page), &pool, false);
        assert!(!shared_guard.is_exclusive());
    }

    #[test]
    fn test_page_guard_deref() {
        let pool = MockBufferPool::new();
        let page = Arc::new(Page::new(99));

        let guard = PageGuard::new(Arc::clone(&page), &pool, true);

        // Should be able to access page fields through deref
        assert_eq!(guard.page_id(), 99);
        assert_eq!(guard.page_type(), PageType::Free);
    }

    #[test]
    fn test_page_guard_into_page() {
        let pool = MockBufferPool::new();
        let page = Arc::new(Page::new(1));

        let guard = PageGuard::new(Arc::clone(&page), &pool, true);
        let taken_page = guard.into_page();

        // Page should still be pinned (pool reference was forgotten)
        assert_eq!(pool.pin_count(1), 1);
        assert_eq!(taken_page.page_id(), 1);

        // Manually unpin to clean up
        pool.unpin(1);
    }
}

//! Parquet import/export support for SQLRustGo
//!
//! Provides ParquetReader and ParquetWriter for COPY FROM/TO Parquet support.
//!
//! # Data Flow
//!
//! - Parquet → Arrow Array → Record → ColumnarStorage (import)
//! - ColumnarStorage → Record → Arrow Array → Parquet (export)

pub mod reader;
pub mod writer;

pub use reader::ParquetReader;
pub use writer::ParquetWriter;

use crate::engine::{Record, SqlResult};

/// Import records from a Parquet file
pub fn import_from_parquet(path: &str, columns: &[String]) -> SqlResult<Vec<Record>> {
    reader::read_parquet_file(path, columns)
}

/// Export records to a Parquet file
pub fn export_to_parquet(path: &str, records: &[Record], column_names: &[String]) -> SqlResult<()> {
    writer::write_parquet_file(path, records, column_names)
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::engine::{ColumnDefinition, TableInfo};
    use tempfile::tempdir;

    #[test]
    fn test_parquet_roundtrip() {
        let dir = tempdir().unwrap();
        let path = dir.path().join("test.parquet");

        // Create test records
        let records = vec![
            vec![
                sqlrustgo_types::Value::Integer(1),
                sqlrustgo_types::Value::Text("hello".to_string()),
            ],
            vec![
                sqlrustgo_types::Value::Integer(2),
                sqlrustgo_types::Value::Text("world".to_string()),
            ],
            vec![
                sqlrustgo_types::Value::Null,
                sqlrustgo_types::Value::Text("null_test".to_string()),
            ],
        ];

        let columns = vec!["id".to_string(), "name".to_string()];

        // Write to Parquet
        writer::write_parquet_file(path.to_str().unwrap(), &records, &columns).unwrap();

        // Read from Parquet
        let read_records = reader::read_parquet_file(path.to_str().unwrap(), &columns).unwrap();

        assert_eq!(records.len(), read_records.len());
        for (original, read) in records.iter().zip(read_records.iter()) {
            assert_eq!(original.len(), read.len());
            for (o, r) in original.iter().zip(read.iter()) {
                assert_eq!(o, r);
            }
        }
    }
}

//! ParquetReader - Read Parquet files into Records
//!
//! Uses Arrow's parquet reader to read Parquet files and convert
//! them to SQLRustGo Record format.

use crate::engine::{Record, SqlError, SqlResult};
use arrow::array::{ArrayRef, BooleanArray, Float64Array, Int64Array, StringArray};
use arrow::datatypes::DataType;
use parquet::arrow::arrow_reader::ParquetRecordBatchReaderBuilder;
use parquet::arrow::ProjectionMask;
use std::fs::File;

/// Read a Parquet file and return records
pub fn read_parquet_file(path: &str, columns: &[String]) -> SqlResult<Vec<Record>> {
    let file = File::open(path)
        .map_err(|e| SqlError::ExecutionError(format!("Failed to open Parquet file: {}", e)))?;

    let builder = ParquetRecordBatchReaderBuilder::try_new(file)
        .map_err(|e| SqlError::ExecutionError(format!("Failed to create Parquet reader: {}", e)))?;

    let record_batch_reader = if columns.is_empty() {
        // Read all columns
        builder.with_batch_size(1024).build().map_err(|e| {
            SqlError::ExecutionError(format!("Failed to build record reader: {}", e))
        })?
    } else {
        // Project only specified columns
        let parquet_schema = builder.parquet_schema();
        let field_indices: Vec<usize> = columns
            .iter()
            .filter_map(|col| {
                parquet_schema
                    .columns()
                    .iter()
                    .position(|c| c.name() == col)
            })
            .collect();

        if field_indices.is_empty() {
            return Err(SqlError::ExecutionError(format!(
                "No matching columns found: {:?}",
                columns
            )));
        }

        let mask = ProjectionMask::leaves(parquet_schema, field_indices.iter().copied());
        builder
            .with_projection(mask)
            .with_batch_size(1024)
            .build()
            .map_err(|e| {
                SqlError::ExecutionError(format!("Failed to build record reader: {}", e))
            })?
    };

    let mut records = Vec::new();

    for batch_result in record_batch_reader {
        let batch = batch_result
            .map_err(|e| SqlError::ExecutionError(format!("Failed to read batch: {}", e)))?;

        let num_rows = batch.num_rows();
        if num_rows == 0 {
            continue;
        }

        let arrays = batch.columns().to_vec();

        // Convert each row to a Record
        for row_idx in 0..num_rows {
            let mut record = Record::new();
            for arr in &arrays {
                let value = extract_value(arr, row_idx)?;
                record.push(value);
            }
            records.push(record);
        }
    }

    Ok(records)
}

/// Extract a Value from an Arrow array at a specific row index
fn extract_value(array: &ArrayRef, row_idx: usize) -> SqlResult<sqlrustgo_types::Value> {
    use sqlrustgo_types::Value;

    if array.is_null(row_idx) {
        return Ok(Value::Null);
    }

    match array.data_type() {
        DataType::Int64 => {
            let arr = array.as_any().downcast_ref::<Int64Array>().ok_or_else(|| {
                SqlError::ExecutionError("Failed to downcast to Int64Array".to_string())
            })?;
            Ok(Value::Integer(arr.value(row_idx)))
        }
        DataType::Float64 => {
            let arr = array
                .as_any()
                .downcast_ref::<Float64Array>()
                .ok_or_else(|| {
                    SqlError::ExecutionError("Failed to downcast to Float64Array".to_string())
                })?;
            Ok(Value::Float(arr.value(row_idx)))
        }
        DataType::Utf8 => {
            let arr = array
                .as_any()
                .downcast_ref::<StringArray>()
                .ok_or_else(|| {
                    SqlError::ExecutionError("Failed to downcast to StringArray".to_string())
                })?;
            Ok(Value::Text(arr.value(row_idx).to_string()))
        }
        DataType::Boolean => {
            let arr = array
                .as_any()
                .downcast_ref::<BooleanArray>()
                .ok_or_else(|| {
                    SqlError::ExecutionError("Failed to downcast to BooleanArray".to_string())
                })?;
            Ok(Value::Boolean(arr.value(row_idx)))
        }
        DataType::Binary => {
            let arr = array
                .as_any()
                .downcast_ref::<arrow::array::BinaryArray>()
                .ok_or_else(|| {
                    SqlError::ExecutionError("Failed to downcast to BinaryArray".to_string())
                })?;
            Ok(Value::Blob(arr.value(row_idx).to_vec()))
        }
        DataType::Date32 => {
            let arr = array
                .as_any()
                .downcast_ref::<arrow::array::Date32Array>()
                .ok_or_else(|| {
                    SqlError::ExecutionError("Failed to downcast to Date32Array".to_string())
                })?;
            Ok(Value::Date(arr.value(row_idx)))
        }
        _ => Err(SqlError::ExecutionError(format!(
            "Unsupported Parquet type: {:?}",
            array.data_type()
        ))),
    }
}

/// ParquetReader struct for reading Parquet files
pub struct ParquetReader {
    path: String,
    columns: Vec<String>,
}

impl ParquetReader {
    /// Create a new ParquetReader
    pub fn new(path: &str, columns: Vec<String>) -> Self {
        Self {
            path: path.to_string(),
            columns,
        }
    }

    /// Read all records from the Parquet file
    pub fn read(&self) -> SqlResult<Vec<Record>> {
        read_parquet_file(&self.path, &self.columns)
    }

    /// Get the number of rows without reading all data
    pub fn row_count(&self) -> SqlResult<usize> {
        let file = File::open(&self.path)
            .map_err(|e| SqlError::ExecutionError(format!("Failed to open Parquet file: {}", e)))?;

        let builder = ParquetRecordBatchReaderBuilder::try_new(file).map_err(|e| {
            SqlError::ExecutionError(format!("Failed to create Parquet reader: {}", e))
        })?;

        Ok(builder.metadata().file_metadata().num_rows() as usize)
    }
}

