//! Read/Write Split Router
//!
//! Provides read/write splitting for master-slave replication:
//! - Route read queries to replicas
//! - Route write queries to master
//! - Load balancing across replicas
//! - Read consistency guarantees

use serde::{Deserialize, Serialize};
use std::net::SocketAddr;
use std::sync::atomic::{AtomicU64, Ordering};
use std::sync::Arc;

#[derive(Debug, Clone)]
pub enum QueryType {
    Read,
    Write,
    Transaction,
}

impl QueryType {
    pub fn is_read(&self) -> bool {
        matches!(self, QueryType::Read)
    }

    pub fn is_write(&self) -> bool {
        matches!(self, QueryType::Write | QueryType::Transaction)
    }
}

#[derive(Debug, Clone, Copy, PartialEq)]
pub enum NodeRole {
    Master,
    Replica,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ReplicaNode {
    pub addr: SocketAddr,
    pub weight: u32,
    pub lag_ms: u64,
    pub is_healthy: bool,
}

impl ReplicaNode {
    pub fn new(addr: SocketAddr) -> Self {
        Self {
            addr,
            weight: 100,
            lag_ms: 0,
            is_healthy: true,
        }
    }

    pub fn with_weight(mut self, weight: u32) -> Self {
        self.weight = weight;
        self
    }

    pub fn with_lag(mut self, lag_ms: u64) -> Self {
        self.lag_ms = lag_ms;
        self
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ReadWriteSplitConfig {
    pub master_addr: SocketAddr,
    pub replica_addrs: Vec<ReplicaNode>,
    pub strategy: LoadBalanceStrategy,
    pub consistency_mode: ConsistencyMode,
    pub max_lag_ms: u64,
}

impl Default for ReadWriteSplitConfig {
    fn default() -> Self {
        Self {
            master_addr: "127.0.0.1:3306".parse().unwrap(),
            replica_addrs: Vec::new(),
            strategy: LoadBalanceStrategy::RoundRobin,
            consistency_mode: ConsistencyMode::Eventual,
            max_lag_ms: 100,
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Serialize, Deserialize)]
pub enum LoadBalanceStrategy {
    RoundRobin,
    WeightedRoundRobin,
    LeastConnections,
    LeastLag,
    Random,
}

#[derive(Debug, Clone, Copy, PartialEq, Serialize, Deserialize)]
pub enum ConsistencyMode {
    Strong,
    Eventual,
    Session,
}

pub struct ReadWriteRouter {
    config: ReadWriteSplitConfig,
    replica_index: Arc<AtomicU64>,
    connection_count: Arc<AtomicU64>,
}

impl ReadWriteRouter {
    pub fn new(config: ReadWriteSplitConfig) -> Self {
        Self {
            config,
            replica_index: Arc::new(AtomicU64::new(0)),
            connection_count: Arc::new(AtomicU64::new(0)),
        }
    }

    pub fn route(&self, query_type: QueryType) -> RouteResult {
        match query_type {
            QueryType::Read => self.route_read(),
            QueryType::Write | QueryType::Transaction => self.route_write(),
        }
    }

    fn route_write(&self) -> RouteResult {
        RouteResult {
            target_addr: self.config.master_addr,
            role: NodeRole::Master,
            is_read: false,
        }
    }

    fn route_read(&self) -> RouteResult {
        let replicas: Vec<_> = self
            .config
            .replica_addrs
            .iter()
            .filter(|r| r.is_healthy && r.lag_ms <= self.config.max_lag_ms)
            .collect();

        if replicas.is_empty() {
            return RouteResult {
                target_addr: self.config.master_addr,
                role: NodeRole::Master,
                is_read: true,
            };
        }

        let target = match self.config.strategy {
            LoadBalanceStrategy::RoundRobin => self.select_round_robin(&replicas),
            LoadBalanceStrategy::WeightedRoundRobin => self.select_weighted_round_robin(&replicas),
            LoadBalanceStrategy::LeastConnections => self.select_least_connections(&replicas),
            LoadBalanceStrategy::LeastLag => self.select_least_lag(&replicas),
            LoadBalanceStrategy::Random => self.select_random(&replicas),
        };

        self.connection_count.fetch_add(1, Ordering::SeqCst);

        RouteResult {
            target_addr: target.addr,
            role: NodeRole::Replica,
            is_read: true,
        }
    }

    fn select_round_robin<'a>(&self, replicas: &'a [&ReplicaNode]) -> &'a ReplicaNode {
        let index = self.replica_index.fetch_add(1, Ordering::SeqCst) as usize;
        replicas[index % replicas.len()]
    }

    fn select_weighted_round_robin<'a>(&self, replicas: &'a [&ReplicaNode]) -> &'a ReplicaNode {
        let total_weight: u32 = replicas.iter().map(|r| r.weight).sum();
        if total_weight == 0 {
            return replicas[0];
        }

        let mut random_weight =
            (self.replica_index.fetch_add(1, Ordering::SeqCst) % total_weight as u64) as u32;

        for replica in replicas {
            if random_weight < replica.weight {
                return replica;
            }
            random_weight -= replica.weight;
        }

        replicas[0]
    }

    fn select_least_connections<'a>(&self, replicas: &'a [&ReplicaNode]) -> &'a ReplicaNode {
        self.connection_count.fetch_add(1, Ordering::SeqCst);
        let index = self.replica_index.fetch_add(1, Ordering::SeqCst) as usize;
        replicas[index % replicas.len()]
    }

    fn select_least_lag<'a>(&self, replicas: &'a [&ReplicaNode]) -> &'a ReplicaNode {
        replicas
            .iter()
            .min_by_key(|r| r.lag_ms)
            .unwrap_or(&replicas[0])
    }

    fn select_random<'a>(&self, replicas: &'a [&ReplicaNode]) -> &'a ReplicaNode {
        use std::time::{SystemTime, UNIX_EPOCH};
        let seed = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .subsec_nanos() as usize;
        &replicas[seed % replicas.len()]
    }

    pub fn add_replica(&mut self, replica: ReplicaNode) {
        self.config.replica_addrs.push(replica);
    }

    pub fn remove_replica(&mut self, addr: SocketAddr) {
        self.config.replica_addrs.retain(|r| r.addr != addr);
    }

    pub fn update_replica_lag(&mut self, addr: SocketAddr, lag_ms: u64) {
        if let Some(replica) = self
            .config
            .replica_addrs
            .iter_mut()
            .find(|r| r.addr == addr)
        {
            replica.lag_ms = lag_ms;
        }
    }

    pub fn set_replica_health(&mut self, addr: SocketAddr, is_healthy: bool) {
        if let Some(replica) = self
            .config
            .replica_addrs
            .iter_mut()
            .find(|r| r.addr == addr)
        {
            replica.is_healthy = is_healthy;
        }
    }

    pub fn get_master_addr(&self) -> SocketAddr {
        self.config.master_addr
    }

    pub fn get_replica_addrs(&self) -> Vec<SocketAddr> {
        self.config.replica_addrs.iter().map(|r| r.addr).collect()
    }

    pub fn get_healthy_replica_count(&self) -> usize {
        self.config
            .replica_addrs
            .iter()
            .filter(|r| r.is_healthy)
            .count()
    }

    pub fn release_connection(&self) {
        self.connection_count.fetch_sub(1, Ordering::SeqCst);
    }
}

#[derive(Debug, Clone)]
pub struct RouteResult {
    pub target_addr: SocketAddr,
    pub role: NodeRole,
    pub is_read: bool,
}

pub struct ConnectionPool {
    master_pool: Vec<Connection>,
    replica_pools: Vec<Vec<Connection>>,
    config: ReadWriteSplitConfig,
}

impl ConnectionPool {
    pub fn new(config: ReadWriteSplitConfig) -> Self {
        Self {
            master_pool: Vec::new(),
            replica_pools: Vec::new(),
            config,
        }
    }

    pub fn get_connection(&self, role: NodeRole) -> Option<&Connection> {
        match role {
            NodeRole::Master => self.master_pool.first(),
            NodeRole::Replica => self.replica_pools.first()?.first(),
        }
    }

    pub fn return_connection(&self, _conn: &Connection) {}
}

#[derive(Debug, Clone)]
pub struct Connection {
    pub addr: SocketAddr,
    pub is_connected: bool,
}

pub struct ReadAfterWriteConsistency {
    master_position: Arc<AtomicU64>,
    replica_positions: Arc<RwLock<HashMap<SocketAddr, u64>>>,
    config: ReadWriteSplitConfig,
}

use std::collections::HashMap;
use std::sync::RwLock;

impl ReadAfterWriteConsistency {
    pub fn new(config: ReadWriteSplitConfig) -> Self {
        Self {
            master_position: Arc::new(AtomicU64::new(0)),
            replica_positions: Arc::new(RwLock::new(HashMap::new())),
            config,
        }
    }

    pub fn record_master_write(&self, lsn: u64) {
        self.master_position.store(lsn, Ordering::SeqCst);
    }

    pub fn record_replica_position(&self, addr: SocketAddr, lsn: u64) {
        if let Ok(mut positions) = self.replica_positions.write() {
            positions.insert(addr, lsn);
        }
    }

    pub fn wait_for_replication(&self, target_addr: SocketAddr) -> bool {
        let master_lsn = self.master_position.load(Ordering::SeqCst);

        if let Ok(positions) = self.replica_positions.read() {
            if let Some(&replica_lsn) = positions.get(&target_addr) {
                return replica_lsn >= master_lsn;
            }
        }

        false
    }

    pub fn ensure_session_consistency(&self, replica_addr: SocketAddr) -> bool {
        match self.config.consistency_mode {
            ConsistencyMode::Strong => self.wait_for_replication(replica_addr),
            ConsistencyMode::Eventual => true,
            ConsistencyMode::Session => self.wait_for_replication(replica_addr),
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn create_test_config() -> ReadWriteSplitConfig {
        ReadWriteSplitConfig {
            master_addr: "127.0.0.1:3306".parse().unwrap(),
            replica_addrs: vec![
                ReplicaNode::new("127.0.0.1:3307".parse().unwrap()).with_weight(100),
                ReplicaNode::new("127.0.0.1:3308".parse().unwrap()).with_weight(50),
            ],
            strategy: LoadBalanceStrategy::RoundRobin,
            consistency_mode: ConsistencyMode::Eventual,
            max_lag_ms: 100,
        }
    }

    #[test]
    fn test_query_type_classification() {
        assert!(QueryType::Read.is_read());
        assert!(!QueryType::Read.is_write());

        assert!(QueryType::Write.is_write());
        assert!(!QueryType::Write.is_read());

        assert!(QueryType::Transaction.is_write());
    }

    #[test]
    fn test_router_write_route() {
        let config = create_test_config();
        let router = ReadWriteRouter::new(config);

        let result = router.route(QueryType::Write);

        assert_eq!(result.target_addr, "127.0.0.1:3306".parse().unwrap());
        assert_eq!(result.role, NodeRole::Master);
        assert!(!result.is_read);
    }

    #[test]
    fn test_router_read_route() {
        let config = create_test_config();
        let router = ReadWriteRouter::new(config);

        let result = router.route(QueryType::Read);

        assert!(result.is_read);
        assert_eq!(result.role, NodeRole::Replica);
    }

    #[test]
    fn test_router_multiple_reads_distributed() {
        let config = create_test_config();
        let router = ReadWriteRouter::new(config);

        let mut targets = Vec::new();
        for _ in 0..4 {
            targets.push(router.route(QueryType::Read).target_addr);
        }

        let unique: Vec<_> = targets.iter().collect();
        assert!(unique.len() >= 1);
    }

    #[test]
    fn test_replica_node_creation() {
        let replica = ReplicaNode::new("127.0.0.1:3307".parse().unwrap());

        assert_eq!(replica.weight, 100);
        assert_eq!(replica.lag_ms, 0);
        assert!(replica.is_healthy);
    }

    #[test]
    fn test_replica_node_with_lag() {
        let replica = ReplicaNode::new("127.0.0.1:3307".parse().unwrap()).with_lag(50);

        assert_eq!(replica.lag_ms, 50);
    }

    #[test]
    fn test_load_balance_strategy_variants() {
        assert_eq!(
            LoadBalanceStrategy::RoundRobin,
            LoadBalanceStrategy::RoundRobin
        );
        assert_eq!(LoadBalanceStrategy::LeastLag, LoadBalanceStrategy::LeastLag);
    }

    #[test]
    fn test_consistency_mode_variants() {
        assert_eq!(ConsistencyMode::Strong, ConsistencyMode::Strong);
        assert_eq!(ConsistencyMode::Eventual, ConsistencyMode::Eventual);
        assert_eq!(ConsistencyMode::Session, ConsistencyMode::Session);
    }

    #[test]
    fn test_read_write_router_add_replica() {
        let config = create_test_config();
        let mut router = ReadWriteRouter::new(config);

        router.add_replica(ReplicaNode::new("127.0.0.1:3309".parse().unwrap()));

        assert_eq!(router.get_replica_addrs().len(), 3);
    }

    #[test]
    fn test_read_write_router_remove_replica() {
        let config = create_test_config();
        let mut router = ReadWriteRouter::new(config);

        router.remove_replica("127.0.0.1:3307".parse().unwrap());

        assert_eq!(router.get_replica_addrs().len(), 1);
    }

    #[test]
    fn test_route_result_fields() {
        let result = RouteResult {
            target_addr: "127.0.0.1:3306".parse().unwrap(),
            role: NodeRole::Master,
            is_read: false,
        };

        assert_eq!(result.target_addr, "127.0.0.1:3306".parse().unwrap());
        assert_eq!(result.role, NodeRole::Master);
        assert!(!result.is_read);
    }

    #[test]
    fn test_read_after_write_consistency() {
        let config = create_test_config();
        let consistency = ReadAfterWriteConsistency::new(config);

        consistency.record_master_write(1000);

        consistency.record_replica_position("127.0.0.1:3307".parse().unwrap(), 1001);

        assert!(consistency.wait_for_replication("127.0.0.1:3307".parse().unwrap()));
    }

    #[test]
    fn test_read_write_split_config_default() {
        let config = ReadWriteSplitConfig::default();

        assert_eq!(config.strategy, LoadBalanceStrategy::RoundRobin);
        assert_eq!(config.consistency_mode, ConsistencyMode::Eventual);
        assert_eq!(config.max_lag_ms, 100);
    }

    #[test]
    fn test_connection_struct() {
        let conn = Connection {
            addr: "127.0.0.1:3306".parse().unwrap(),
            is_connected: true,
        };

        assert_eq!(conn.addr, "127.0.0.1:3306".parse().unwrap());
        assert!(conn.is_connected);
    }
}

//! Replication module for master-slave replication
//!
//! This module provides the foundation for async replication:
//! - Binlog events for DDL/DML/Commit
//! - Master: binlog writer
//! - Slave: IO thread (fetch) + SQL thread (replay)
//! - Simple failover (heartbeat monitoring, leader election)

use std::io::{Read, Write};
use std::path::PathBuf;
use std::sync::{Arc, Mutex};
use std::thread;
use std::time::Duration;

use serde::{Deserialize, Serialize};

/// Binlog event types
#[derive(Debug, Clone, Copy, PartialEq, Serialize, Deserialize)]
pub enum BinlogEventType {
    /// DDL: CREATE/ALTER/DROP
    Ddl = 1,
    /// DML: INSERT/UPDATE/DELETE
    Dml = 2,
    /// Transaction commit
    Commit = 3,
    /// Transaction rollback
    Rollback = 4,
    /// Heartbeat
    Heartbeat = 5,
}

impl BinlogEventType {
    pub fn from_u8(v: u8) -> Option<Self> {
        match v {
            1 => Some(BinlogEventType::Ddl),
            2 => Some(BinlogEventType::Dml),
            3 => Some(BinlogEventType::Commit),
            4 => Some(BinlogEventType::Rollback),
            5 => Some(BinlogEventType::Heartbeat),
            _ => None,
        }
    }
}

/// Binlog event
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BinlogEvent {
    /// Event type
    pub event_type: BinlogEventType,
    /// Transaction ID
    pub tx_id: u64,
    /// Table ID
    pub table_id: u64,
    /// Database name
    pub database: String,
    /// Table name
    pub table: String,
    /// SQL statement (for DDL/DML)
    pub sql: Option<String>,
    /// Row data (for DML)
    pub row_data: Option<Vec<u8>>,
    /// Log sequence number
    pub lsn: u64,
    /// Timestamp
    pub timestamp: u64,
}

impl BinlogEvent {
    /// Serialize to bytes
    pub fn to_bytes(&self) -> Vec<u8> {
        let mut bytes = Vec::new();

        // Event type (1 byte)
        bytes.push(self.event_type as u8);

        // TX ID (8 bytes)
        bytes.extend_from_slice(&self.tx_id.to_le_bytes());

        // Table ID (8 bytes)
        bytes.extend_from_slice(&self.table_id.to_le_bytes());

        // Database length + name
        let db_bytes = self.database.as_bytes();
        bytes.extend_from_slice(&(db_bytes.len() as u32).to_le_bytes());
        bytes.extend_from_slice(db_bytes);

        // Table length + name
        let table_bytes = self.table.as_bytes();
        bytes.extend_from_slice(&(table_bytes.len() as u32).to_le_bytes());
        bytes.extend_from_slice(table_bytes);

        // SQL length + content
        match &self.sql {
            Some(sql) => {
                let sql_bytes = sql.as_bytes();
                bytes.extend_from_slice(&(sql_bytes.len() as u32).to_le_bytes());
                bytes.extend_from_slice(sql_bytes);
            }
            None => {
                bytes.extend_from_slice(&0u32.to_le_bytes());
            }
        }

        // Row data length + content
        match &self.row_data {
            Some(data) => {
                bytes.extend_from_slice(&(data.len() as u32).to_le_bytes());
                bytes.extend_from_slice(data);
            }
            None => {
                bytes.extend_from_slice(&0u32.to_le_bytes());
            }
        }

        // LSN (8 bytes)
        bytes.extend_from_slice(&self.lsn.to_le_bytes());

        // Timestamp (8 bytes)
        bytes.extend_from_slice(&self.timestamp.to_le_bytes());

        bytes
    }

    /// Deserialize from bytes
    pub fn from_bytes(data: &[u8]) -> Option<Self> {
        if data.len() < 25 {
            return None;
        }

        let mut offset = 0;

        // Event type
        let event_type = BinlogEventType::from_u8(data[offset])?;
        offset += 1;

        // TX ID
        let tx_id = u64::from_le_bytes([
            data[offset],
            data[offset + 1],
            data[offset + 2],
            data[offset + 3],
            data[offset + 4],
            data[offset + 5],
            data[offset + 6],
            data[offset + 7],
        ]);
        offset += 8;

        // Table ID
        let table_id = u64::from_le_bytes([
            data[offset],
            data[offset + 1],
            data[offset + 2],
            data[offset + 3],
            data[offset + 4],
            data[offset + 5],
            data[offset + 6],
            data[offset + 7],
        ]);
        offset += 8;

        // Database
        let db_len = u32::from_le_bytes([
            data[offset],
            data[offset + 1],
            data[offset + 2],
            data[offset + 3],
        ]) as usize;
        offset += 4;
        let database = String::from_utf8(data[offset..offset + db_len].to_vec()).ok()?;
        offset += db_len;

        // Table
        let table_len = u32::from_le_bytes([
            data[offset],
            data[offset + 1],
            data[offset + 2],
            data[offset + 3],
        ]) as usize;
        offset += 4;
        let table = String::from_utf8(data[offset..offset + table_len].to_vec()).ok()?;
        offset += table_len;

        // SQL
        let sql_len = u32::from_le_bytes([
            data[offset],
            data[offset + 1],
            data[offset + 2],
            data[offset + 3],
        ]) as usize;
        offset += 4;
        let sql = if sql_len > 0 {
            Some(String::from_utf8(data[offset..offset + sql_len].to_vec()).ok()?)
        } else {
            None
        };
        offset += sql_len;

        // Row data
        let data_len = u32::from_le_bytes([
            data[offset],
            data[offset + 1],
            data[offset + 2],
            data[offset + 3],
        ]) as usize;
        offset += 4;
        let row_data = if data_len > 0 {
            Some(data[offset..offset + data_len].to_vec())
        } else {
            None
        };
        offset += data_len;

        // LSN
        let lsn = u64::from_le_bytes([
            data[offset],
            data[offset + 1],
            data[offset + 2],
            data[offset + 3],
            data[offset + 4],
            data[offset + 5],
            data[offset + 6],
            data[offset + 7],
        ]);
        offset += 8;

        // Timestamp
        let timestamp = u64::from_le_bytes([
            data[offset],
            data[offset + 1],
            data[offset + 2],
            data[offset + 3],
            data[offset + 4],
            data[offset + 5],
            data[offset + 6],
            data[offset + 7],
        ]);

        Some(BinlogEvent {
            event_type,
            tx_id,
            table_id,
            database,
            table,
            sql,
            row_data,
            lsn,
            timestamp,
        })
    }
}

/// Binlog writer (Master side)
pub struct BinlogWriter {
    path: PathBuf,
    lsn: u64,
    position: u64,
}

impl BinlogWriter {
    pub fn new(path: PathBuf) -> std::io::Result<Self> {
        Ok(Self {
            path,
            lsn: 0,
            position: 0,
        })
    }

    /// Write event to binlog
    pub fn write_event(&mut self, event: &BinlogEvent) -> std::io::Result<u64> {
        let lsn = self.lsn;
        let mut event = event.clone();
        event.lsn = lsn;

        let bytes = event.to_bytes();

        // Write length prefix (4 bytes) + data
        let mut file = std::fs::OpenOptions::new()
            .create(true)
            .append(true)
            .open(&self.path)?;

        file.write_all(&(bytes.len() as u32).to_le_bytes())?;
        file.write_all(&bytes)?;
        file.flush()?;

        self.lsn += 1;
        self.position += bytes.len() as u64 + 4;

        Ok(lsn)
    }

    /// Get current LSN
    pub fn current_lsn(&self) -> u64 {
        self.lsn
    }

    /// Get current position
    pub fn position(&self) -> u64 {
        self.position
    }
}

/// Binlog reader (Slave side)
pub struct BinlogReader {
    path: PathBuf,
    lsn: u64,
}

impl BinlogReader {
    pub fn new(path: PathBuf) -> std::io::Result<Self> {
        Ok(Self { path, lsn: 0 })
    }

    /// Read events from current LSN
    pub fn read_from(&mut self, start_lsn: u64) -> std::io::Result<Vec<BinlogEvent>> {
        let mut file = std::fs::File::open(&self.path)?;
        let mut events = Vec::new();
        let mut current_lsn: u64 = 0;

        loop {
            // Read length prefix
            let mut len_bytes = [0u8; 4];
            match file.read_exact(&mut len_bytes) {
                Ok(_) => {}
                Err(e) if e.kind() == std::io::ErrorKind::UnexpectedEof => break,
                Err(e) => return Err(e),
            }

            let len = u32::from_le_bytes(len_bytes) as usize;

            // Read event data
            let mut data = vec![0u8; len];
            file.read_exact(&mut data)?;

            if let Some(event) = BinlogEvent::from_bytes(&data) {
                if event.lsn >= start_lsn {
                    events.push(event.clone());
                }
                current_lsn = event.lsn;
            }
        }

        self.lsn = current_lsn + 1;
        Ok(events)
    }

    /// Get current LSN
    pub fn current_lsn(&self) -> u64 {
        self.lsn
    }
}

/// Replication config
#[derive(Debug, Clone)]
pub struct ReplicationConfig {
    /// Master host
    pub master_host: String,
    /// Master port
    pub master_port: u16,
    /// Slave ID
    pub slave_id: u32,
    /// Replica lag threshold (ms)
    pub lag_threshold_ms: u64,
}

impl Default for ReplicationConfig {
    fn default() -> Self {
        Self {
            master_host: "127.0.0.1".to_string(),
            master_port: 3306,
            slave_id: 1,
            lag_threshold_ms: 1000,
        }
    }
}

/// Master node for replication
#[allow(dead_code)]
pub struct MasterNode {
    binlog_writer: Arc<Mutex<BinlogWriter>>,
    config: ReplicationConfig,
}

impl MasterNode {
    pub fn new(binlog_path: PathBuf, config: ReplicationConfig) -> std::io::Result<Self> {
        let writer = BinlogWriter::new(binlog_path)?;
        Ok(Self {
            binlog_writer: Arc::new(Mutex::new(writer)),
            config,
        })
    }

    /// Write DDL event
    pub fn write_ddl(
        &self,
        tx_id: u64,
        table_id: u64,
        database: &str,
        table: &str,
        sql: &str,
    ) -> std::io::Result<u64> {
        let event = BinlogEvent {
            event_type: BinlogEventType::Ddl,
            tx_id,
            table_id,
            database: database.to_string(),
            table: table.to_string(),
            sql: Some(sql.to_string()),
            row_data: None,
            lsn: 0,
            timestamp: std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_secs(),
        };

        let mut writer = self.binlog_writer.lock().unwrap();
        writer.write_event(&event)
    }

    /// Write DML event
    pub fn write_dml(
        &self,
        tx_id: u64,
        table_id: u64,
        database: &str,
        table: &str,
        sql: Option<String>,
        row_data: Option<Vec<u8>>,
    ) -> std::io::Result<u64> {
        let event = BinlogEvent {
            event_type: BinlogEventType::Dml,
            tx_id,
            table_id,
            database: database.to_string(),
            table: table.to_string(),
            sql,
            row_data,
            lsn: 0,
            timestamp: std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_secs(),
        };

        let mut writer = self.binlog_writer.lock().unwrap();
        writer.write_event(&event)
    }

    /// Write commit event
    pub fn write_commit(&self, tx_id: u64) -> std::io::Result<u64> {
        let event = BinlogEvent {
            event_type: BinlogEventType::Commit,
            tx_id,
            table_id: 0,
            database: String::new(),
            table: String::new(),
            sql: None,
            row_data: None,
            lsn: 0,
            timestamp: std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_secs(),
        };

        let mut writer = self.binlog_writer.lock().unwrap();
        writer.write_event(&event)
    }

    /// Get current binlog position
    pub fn binlog_position(&self) -> u64 {
        let writer = self.binlog_writer.lock().unwrap();
        writer.position()
    }
}

/// Slave node for replication
#[allow(dead_code)]
pub struct SlaveNode {
    binlog_path: PathBuf,
    config: ReplicationConfig,
    master_lsn: Arc<Mutex<u64>>,
    is_running: Arc<Mutex<bool>>,
}

impl SlaveNode {
    pub fn new(binlog_path: PathBuf, config: ReplicationConfig) -> Self {
        Self {
            binlog_path,
            config,
            master_lsn: Arc::new(Mutex::new(0)),
            is_running: Arc::new(Mutex::new(false)),
        }
    }

    /// Start IO thread (fetch binlog from master)
    pub fn start_io_thread(&self) {
        let binlog_path = self.binlog_path.clone();
        let master_lsn = self.master_lsn.clone();
        let is_running = self.is_running.clone();

        *is_running.lock().unwrap() = true;

        thread::spawn(move || {
            let mut reader = match BinlogReader::new(binlog_path) {
                Ok(r) => r,
                Err(e) => {
                    eprintln!("Failed to create binlog reader: {}", e);
                    return;
                }
            };

            loop {
                if !*is_running.lock().unwrap() {
                    break;
                }

                let start_lsn = *master_lsn.lock().unwrap();

                match reader.read_from(start_lsn) {
                    Ok(events) => {
                        for event in &events {
                            let mut lsn = master_lsn.lock().unwrap();
                            *lsn = event.lsn;
                        }
                    }
                    Err(e) => {
                        eprintln!("Error reading binlog: {}", e);
                    }
                }

                thread::sleep(Duration::from_millis(100));
            }
        });
    }

    /// Start SQL thread (replay events)
    pub fn start_sql_thread<F>(&self, mut replay_fn: F)
    where
        F: FnMut(BinlogEvent) -> std::io::Result<()> + Send + 'static,
    {
        let binlog_path = self.binlog_path.clone();
        let master_lsn = self.master_lsn.clone();
        let is_running = self.is_running.clone();

        thread::spawn(move || {
            let mut reader = match BinlogReader::new(binlog_path) {
                Ok(r) => r,
                Err(e) => {
                    eprintln!("Failed to create binlog reader: {}", e);
                    return;
                }
            };

            loop {
                if !*is_running.lock().unwrap() {
                    break;
                }

                let start_lsn = *master_lsn.lock().unwrap();

                match reader.read_from(start_lsn) {
                    Ok(events) => {
                        for event in events {
                            if let Err(e) = replay_fn(event.clone()) {
                                eprintln!("Error replaying event: {}", e);
                            }
                        }
                    }
                    Err(e) => {
                        eprintln!("Error reading binlog: {}", e);
                    }
                }

                thread::sleep(Duration::from_millis(100));
            }
        });
    }

    /// Stop replication
    pub fn stop(&self) {
        *self.is_running.lock().unwrap() = false;
    }

    /// Get replication lag
    pub fn replication_lag(&self) -> u64 {
        // Simplified: return 0 (in production, compare timestamps)
        0
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::fs;

    #[test]
    fn test_binlog_event_serialize() {
        let event = BinlogEvent {
            event_type: BinlogEventType::Dml,
            tx_id: 123,
            table_id: 456,
            database: "test_db".to_string(),
            table: "users".to_string(),
            sql: Some("INSERT INTO users VALUES (1)".to_string()),
            row_data: None,
            lsn: 0,
            timestamp: 1234567890,
        };

        let bytes = event.to_bytes();
        let parsed = BinlogEvent::from_bytes(&bytes).unwrap();

        assert_eq!(parsed.event_type, BinlogEventType::Dml);
        assert_eq!(parsed.tx_id, 123);
        assert_eq!(parsed.table_id, 456);
        assert_eq!(parsed.database, "test_db");
    }

    #[test]
    fn test_binlog_event_ddl() {
        let event = BinlogEvent {
            event_type: BinlogEventType::Ddl,
            tx_id: 100,
            table_id: 1,
            database: "mydb".to_string(),
            table: "orders".to_string(),
            sql: Some("CREATE TABLE orders (id INT)".to_string()),
            row_data: None,
            lsn: 10,
            timestamp: 1234567890,
        };

        let bytes = event.to_bytes();
        let parsed = BinlogEvent::from_bytes(&bytes).unwrap();

        assert_eq!(parsed.event_type, BinlogEventType::Ddl);
        assert_eq!(parsed.sql.as_ref().unwrap(), "CREATE TABLE orders (id INT)");
    }

    #[test]
    fn test_binlog_event_commit() {
        let event = BinlogEvent {
            event_type: BinlogEventType::Commit,
            tx_id: 999,
            table_id: 0,
            database: "test".to_string(),
            table: "".to_string(),
            sql: None,
            row_data: None,
            lsn: 100,
            timestamp: 1234567890,
        };

        let bytes = event.to_bytes();
        let parsed = BinlogEvent::from_bytes(&bytes).unwrap();

        assert_eq!(parsed.event_type, BinlogEventType::Commit);
        assert_eq!(parsed.tx_id, 999);
    }

    #[test]
    fn test_binlog_event_heartbeat() {
        let event = BinlogEvent {
            event_type: BinlogEventType::Heartbeat,
            tx_id: 0,
            table_id: 0,
            database: "".to_string(),
            table: "".to_string(),
            sql: None,
            row_data: None,
            lsn: 50,
            timestamp: 1234567890,
        };

        let bytes = event.to_bytes();
        let parsed = BinlogEvent::from_bytes(&bytes).unwrap();

        assert_eq!(parsed.event_type, BinlogEventType::Heartbeat);
    }

    #[test]
    fn test_binlog_writer_and_reader() {
        let temp_dir = std::env::temp_dir();
        let binlog_path = temp_dir.join("test_binlog_replication.binlog");

        let _ = fs::remove_file(&binlog_path);

        let mut writer = BinlogWriter::new(binlog_path.clone()).unwrap();

        let event1 = BinlogEvent {
            event_type: BinlogEventType::Dml,
            tx_id: 1,
            table_id: 1,
            database: "test".to_string(),
            table: "users".to_string(),
            sql: Some("INSERT".to_string()),
            row_data: None,
            lsn: 0,
            timestamp: 1000,
        };

        let lsn1 = writer.write_event(&event1).unwrap();
        assert_eq!(lsn1, 0);

        let event2 = BinlogEvent {
            event_type: BinlogEventType::Commit,
            tx_id: 1,
            table_id: 0,
            database: "test".to_string(),
            table: "".to_string(),
            sql: None,
            row_data: None,
            lsn: 0,
            timestamp: 1001,
        };

        let lsn2 = writer.write_event(&event2).unwrap();
        assert_eq!(lsn2, 1);

        drop(writer);

        let mut reader = BinlogReader::new(binlog_path.clone()).unwrap();
        let events = reader.read_from(0).unwrap();

        assert_eq!(events.len(), 2);
        assert_eq!(events[0].event_type, BinlogEventType::Dml);
        assert_eq!(events[1].event_type, BinlogEventType::Commit);

        let _ = fs::remove_file(&binlog_path);
    }

    #[test]
    fn test_replication_config_default() {
        let config = ReplicationConfig::default();
        assert_eq!(config.master_port, 3306);
        assert_eq!(config.slave_id, 1);
        assert_eq!(config.lag_threshold_ms, 1000);
    }

    #[test]
    fn test_binlog_event_type_from_u8() {
        assert_eq!(BinlogEventType::from_u8(1), Some(BinlogEventType::Ddl));
        assert_eq!(BinlogEventType::from_u8(2), Some(BinlogEventType::Dml));
        assert_eq!(BinlogEventType::from_u8(3), Some(BinlogEventType::Commit));
        assert_eq!(BinlogEventType::from_u8(4), Some(BinlogEventType::Rollback));
        assert_eq!(
            BinlogEventType::from_u8(5),
            Some(BinlogEventType::Heartbeat)
        );
        assert_eq!(BinlogEventType::from_u8(0), None);
        assert_eq!(BinlogEventType::from_u8(100), None);
    }
}

//! Replication Lag Monitor
//!
//! Monitors replication lag between master and slave nodes.
//! Alerts when lag exceeds configured threshold.

use std::sync::atomic::{AtomicU64, Ordering};
use std::sync::Arc;
use std::time::{Duration, Instant};

pub struct ReplicationLagMonitor {
    master_lsn: Arc<AtomicU64>,
    master_timestamp: Arc<AtomicU64>,
    slave_applied_lsn: Arc<AtomicU64>,
    slave_applied_timestamp: Arc<AtomicU64>,
    lag_threshold_ms: u64,
    last_warning_time: Arc<AtomicU64>,
    warning_interval_ms: u64,
}

impl ReplicationLagMonitor {
    pub fn new(lag_threshold_ms: u64) -> Self {
        Self {
            master_lsn: Arc::new(AtomicU64::new(0)),
            master_timestamp: Arc::new(AtomicU64::new(0)),
            slave_applied_lsn: Arc::new(AtomicU64::new(0)),
            slave_applied_timestamp: Arc::new(AtomicU64::new(0)),
            lag_threshold_ms,
            last_warning_time: Arc::new(AtomicU64::new(0)),
            warning_interval_ms: 60_000,
        }
    }

    pub fn with_warning_interval(mut self, interval_ms: u64) -> Self {
        self.warning_interval_ms = interval_ms;
        self
    }

    pub fn update_master_info(&self, lsn: u64, timestamp_ms: u64) {
        self.master_lsn.store(lsn, Ordering::SeqCst);
        self.master_timestamp.store(timestamp_ms, Ordering::SeqCst);
    }

    pub fn report_applied(&self, lsn: u64) {
        let now = current_timestamp_ms();
        self.slave_applied_lsn.store(lsn, Ordering::SeqCst);
        self.slave_applied_timestamp.store(now, Ordering::SeqCst);
    }

    pub fn current_lag_ms(&self) -> u64 {
        let master_ts = self.master_timestamp.load(Ordering::SeqCst);
        let slave_ts = self.slave_applied_timestamp.load(Ordering::SeqCst);

        if master_ts == 0 || slave_ts == 0 {
            return 0;
        }

        master_ts.saturating_sub(slave_ts)
    }

    pub fn current_lag_events(&self) -> u64 {
        let master_lsn = self.master_lsn.load(Ordering::SeqCst);
        let slave_lsn = self.slave_applied_lsn.load(Ordering::SeqCst);

        master_lsn.saturating_sub(slave_lsn)
    }

    pub fn is_lag_exceeding_threshold(&self) -> bool {
        self.current_lag_ms() > self.lag_threshold_ms
    }

    pub fn should_warn(&self) -> bool {
        let now = current_timestamp_ms();
        let last_warning = self.last_warning_time.load(Ordering::SeqCst);

        if now.saturating_sub(last_warning) >= self.warning_interval_ms {
            self.last_warning_time.store(now, Ordering::SeqCst);
            true
        } else {
            false
        }
    }

    pub fn check_and_warn(&self) -> Option<LagWarning> {
        if self.is_lag_exceeding_threshold() && self.should_warn() {
            Some(LagWarning {
                lag_ms: self.current_lag_ms(),
                lag_events: self.current_lag_events(),
                threshold_ms: self.lag_threshold_ms,
            })
        } else {
            None
        }
    }

    pub fn lag_threshold_ms(&self) -> u64 {
        self.lag_threshold_ms
    }

    pub fn reset(&self) {
        self.master_lsn.store(0, Ordering::SeqCst);
        self.master_timestamp.store(0, Ordering::SeqCst);
        self.slave_applied_lsn.store(0, Ordering::SeqCst);
        self.slave_applied_timestamp.store(0, Ordering::SeqCst);
    }
}

impl Default for ReplicationLagMonitor {
    fn default() -> Self {
        Self::new(1000)
    }
}

impl Clone for ReplicationLagMonitor {
    fn clone(&self) -> Self {
        Self {
            master_lsn: self.master_lsn.clone(),
            master_timestamp: self.master_timestamp.clone(),
            slave_applied_lsn: self.slave_applied_lsn.clone(),
            slave_applied_timestamp: self.slave_applied_timestamp.clone(),
            lag_threshold_ms: self.lag_threshold_ms,
            last_warning_time: self.last_warning_time.clone(),
            warning_interval_ms: self.warning_interval_ms,
        }
    }
}

#[derive(Debug, Clone)]
pub struct LagWarning {
    pub lag_ms: u64,
    pub lag_events: u64,
    pub threshold_ms: u64,
}

impl LagWarning {
    pub fn message(&self) -> String {
        format!(
            "Replication lag warning: {}ms ({} events) exceeds threshold {}ms",
            self.lag_ms, self.lag_events, self.threshold_ms
        )
    }
}

fn current_timestamp_ms() -> u64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap()
        .as_millis() as u64
}

pub struct ReplicationStatus {
    pub master_lsn: u64,
    pub slave_applied_lsn: u64,
    pub lag_ms: u64,
    pub lag_events: u64,
    pub is_healthy: bool,
}

impl ReplicationLagMonitor {
    pub fn status(&self) -> ReplicationStatus {
        let master_lsn = self.master_lsn.load(Ordering::SeqCst);
        let slave_applied_lsn = self.slave_applied_lsn.load(Ordering::SeqCst);
        let lag_ms = self.current_lag_ms();
        let lag_events = self.current_lag_events();

        ReplicationStatus {
            master_lsn,
            slave_applied_lsn,
            lag_ms,
            lag_events,
            is_healthy: !self.is_lag_exceeding_threshold(),
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_lag_monitor_creation() {
        let monitor = ReplicationLagMonitor::new(5000);
        assert_eq!(monitor.lag_threshold_ms(), 5000);
        assert_eq!(monitor.current_lag_ms(), 0);
    }

    #[test]
    fn test_lag_calculation() {
        let monitor = ReplicationLagMonitor::new(1000);

        monitor.update_master_info(100, current_timestamp_ms());

        std::thread::sleep(Duration::from_millis(10));

        monitor.report_applied(50);

        let lag = monitor.current_lag_ms();
        assert!(lag >= 0);
        assert_eq!(monitor.current_lag_events(), 50);
    }

    #[test]
    fn test_threshold_detection() {
        let monitor = ReplicationLagMonitor::new(100);

        monitor.update_master_info(1000, current_timestamp_ms());
        monitor.report_applied(0);

        assert!(monitor.is_lag_exceeding_threshold());
    }

    #[test]
    fn test_no_lag() {
        let monitor = ReplicationLagMonitor::new(1000);

        let now = current_timestamp_ms();
        monitor.update_master_info(100, now);
        monitor.report_applied(100);

        assert!(!monitor.is_lag_exceeding_threshold());
    }

    #[test]
    fn test_warning_rate_limiting() {
        let monitor = ReplicationLagMonitor::new(1).with_warning_interval(1000);

        monitor.update_master_info(100, current_timestamp_ms());
        monitor.report_applied(0);

        assert!(monitor.should_warn());
        assert!(!monitor.should_warn());
    }

    #[test]
    fn test_lag_warning_message() {
        let warning = LagWarning {
            lag_ms: 5000,
            lag_events: 100,
            threshold_ms: 1000,
        };

        let msg = warning.message();
        assert!(msg.contains("5000ms"));
        assert!(msg.contains("100 events"));
        assert!(msg.contains("1000ms"));
    }
}

//! Statistics module for table and column statistics
//!
//! Provides basic statistics collection and storage for query optimization

use std::collections::HashMap;

/// Table statistics
#[derive(Debug, Clone)]
pub struct TableStats {
    /// Table name
    pub table_name: String,
    /// Number of rows
    pub row_count: u64,
    /// Number of data pages
    pub page_count: u32,
    /// Table size in bytes
    pub table_size: u64,
    /// Last updated timestamp
    pub last_updated: u64,
    /// Column statistics
    pub column_stats: HashMap<String, ColumnStats>,
}

impl TableStats {
    pub fn new(table_name: String) -> Self {
        Self {
            table_name,
            row_count: 0,
            page_count: 0,
            table_size: 0,
            last_updated: 0,
            column_stats: HashMap::new(),
        }
    }

    /// Update row count
    pub fn set_row_count(&mut self, count: u64) {
        self.row_count = count;
        self.last_updated = now();
    }

    /// Update page count
    pub fn set_page_count(&mut self, count: u32) {
        self.page_count = count;
        self.last_updated = now();
    }

    /// Update table size
    pub fn set_table_size(&mut self, size: u64) {
        self.table_size = size;
        self.last_updated = now();
    }

    /// Add column statistics
    pub fn add_column_stats(&mut self, column_name: String, stats: ColumnStats) {
        self.column_stats.insert(column_name, stats);
        self.last_updated = now();
    }
}

/// Column statistics
#[derive(Debug, Clone)]
pub struct ColumnStats {
    /// Column name
    pub column_name: String,
    /// Number of null values
    pub null_count: u64,
    /// Number of distinct values
    pub distinct_count: u64,
    /// Minimum value (as bytes for comparison)
    pub min_value: Option<Vec<u8>>,
    /// Maximum value (as bytes for comparison)
    pub max_value: Option<Vec<u8>>,
    /// Average value size
    pub avg_size: f64,
}

impl ColumnStats {
    pub fn new(column_name: String) -> Self {
        Self {
            column_name,
            null_count: 0,
            distinct_count: 0,
            min_value: None,
            max_value: None,
            avg_size: 0.0,
        }
    }

    /// Update with a new value
    pub fn update(&mut self, value: Option<&[u8]>, size: usize) {
        match value {
            Some(v) => {
                // Update min/max
                if let Some(ref min) = self.min_value {
                    if v < min.as_slice() {
                        self.min_value = Some(v.to_vec());
                    }
                } else {
                    self.min_value = Some(v.to_vec());
                }

                if let Some(ref max) = self.max_value {
                    if v > max.as_slice() {
                        self.max_value = Some(v.to_vec());
                    }
                } else {
                    self.max_value = Some(v.to_vec());
                }

                // Update average size
                let total_count = self.distinct_count + self.null_count;
                if total_count > 0 {
                    self.avg_size = (self.avg_size * total_count as f64 + size as f64)
                        / (total_count + 1) as f64;
                } else {
                    self.avg_size = size as f64;
                }

                self.distinct_count += 1;
            }
            None => {
                self.null_count += 1;
            }
        }
    }
}

/// Statistics manager
pub struct StatsManager {
    /// Table statistics
    table_stats: HashMap<String, TableStats>,
}

impl StatsManager {
    pub fn new() -> Self {
        Self {
            table_stats: HashMap::new(),
        }
    }

    /// Get or create table statistics
    pub fn get_or_create_table(&mut self, table_name: &str) -> &mut TableStats {
        self.table_stats
            .entry(table_name.to_string())
            .or_insert_with(|| TableStats::new(table_name.to_string()))
    }

    /// Get table statistics
    pub fn get_table_stats(&self, table_name: &str) -> Option<&TableStats> {
        self.table_stats.get(table_name)
    }

    /// Update table row count
    pub fn update_row_count(&mut self, table_name: &str, count: u64) {
        if let Some(stats) = self.table_stats.get_mut(table_name) {
            stats.set_row_count(count);
        }
    }

    /// Update table page count
    pub fn update_page_count(&mut self, table_name: &str, count: u32) {
        if let Some(stats) = self.table_stats.get_mut(table_name) {
            stats.set_page_count(count);
        }
    }

    /// Update table size
    pub fn update_table_size(&mut self, table_name: &str, size: u64) {
        if let Some(stats) = self.table_stats.get_mut(table_name) {
            stats.set_table_size(size);
        }
    }

    /// Update column statistics
    pub fn update_column_stats(
        &mut self,
        table_name: &str,
        column_name: &str,
        value: Option<&[u8]>,
        size: usize,
    ) {
        let table_stats = self.get_or_create_table(table_name);
        let col_stats = table_stats
            .column_stats
            .entry(column_name.to_string())
            .or_insert_with(|| ColumnStats::new(column_name.to_string()));
        col_stats.update(value, size);
    }

    /// List all tables with statistics
    pub fn list_tables(&self) -> Vec<String> {
        self.table_stats.keys().cloned().collect()
    }

    /// Clear all statistics
    pub fn clear(&mut self) {
        self.table_stats.clear();
    }

    /// Remove table statistics
    pub fn remove_table(&mut self, table_name: &str) {
        self.table_stats.remove(table_name);
    }
}

impl Default for StatsManager {
    fn default() -> Self {
        Self::new()
    }
}

/// Get current timestamp
fn now() -> u64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap()
        .as_secs()
}

